# Intercept all uncaught exceptions and write them to the log
def _helio_excepthook(exc_type, exc_val, exc_tb):
    log.error("UNCAUGHT EXCEPTION", exc_info=(exc_type, exc_val, exc_tb))
    sys.__excepthook__(exc_type, exc_val, exc_tb)
sys.excepthook = _helio_excepthook

# Context manager for timing heavy operations
import contextlib as _contextlib, time as _time
@_contextlib.contextmanager
def log_time(label):
    t0 = _time.perf_counter()
    try:
        yield
    finally:
        dt = _time.perf_counter() - t0
        if dt > 1.0:  # only log if it took >1 second
            log.warning(f"SLOW  {label}  {dt:.2f}s")
        else:
            log.debug(f"OK    {label}  {dt:.3f}s")
