# ── V50 Global Window Focus Fix ───────────────────────────────────────────────
# CustomTkinter CTkToplevel windows render behind the parent on macOS and
# Windows due to a race between Tk's window manager and CTk's draw loop.
# Patch the base class so every popup in the entire app auto-lifts itself
# 50 ms and 200 ms after creation — covers both fast and slow Tk event loops.
# This removes the need to add win.lift() / win.focus_force() to every caller.
_OrigCTkToplevel = ctk.CTkToplevel
class _AutoFocusToplevel(_OrigCTkToplevel):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        def _bring_front():
            try:
                self.lift()
                self.focus_force()
                try:
                    self.attributes('-topmost', True)
                    self.after(350, lambda: self.attributes('-topmost', False))
                except Exception:
                    pass
            except Exception:
                pass
        self.after(50,  _bring_front)
        self.after(200, _bring_front)
ctk.CTkToplevel = _AutoFocusToplevel

# Patch plain tk.Toplevel too (used by Neural RTI, plot windows, etc.)
_OrigTkToplevel = tk.Toplevel
class _AutoFocusTkToplevel(_OrigTkToplevel):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        def _bring_front():
            try: self.lift(); self.focus_force()
            except Exception: pass
        self.after(50,  _bring_front)
        self.after(200, _bring_front)
tk.Toplevel = _AutoFocusTkToplevel
