def _fix_glb_material(glb_path, metallic=0.0, roughness=0.65, double_sided=True):
    """
    Post-process a GLB file to set correct PBR material properties.

    This operates on the binary GLB format directly — parses the JSON chunk,
    sets metallicFactor/roughnessFactor/doubleSided on every material, then
    rewrites the file.  Vertex colours and geometry are NEVER touched.

    This is vastly more reliable than manipulating trimesh's Visual classes
    (TextureVisuals destroys vertex colours; ColorVisuals ignores PBR props).

    Without this fix, Sketchfab/Blender/Three.js may use default metallic ~0.5
    which makes the model appear completely dark with vertex colours.
    """
    import struct, json as _json
    try:
        with open(glb_path, 'rb') as f:
            data = f.read()
        if len(data) < 20 or data[:4] != b'glTF':
            return  # not a valid GLB
        magic, version, total_len = struct.unpack_from('<III', data, 0)
        json_len, json_type = struct.unpack_from('<II', data, 12)
        json_bytes = data[20:20 + json_len]
        bin_chunk = data[20 + json_len:]   # binary chunk(s) — pass through untouched

        gltf = _json.loads(json_bytes)

        # Fix every material
        for mat in gltf.get('materials', []):
            pbr = mat.setdefault('pbrMetallicRoughness', {})
            pbr['metallicFactor'] = metallic
            pbr['roughnessFactor'] = roughness
            # Keep baseColorFactor white so vertex colours come through at full brightness
            if 'baseColorFactor' not in pbr:
                pbr['baseColorFactor'] = [1.0, 1.0, 1.0, 1.0]
            if double_sided:
                mat['doubleSided'] = True
            # Remove emissive factor if it's black (trimesh sometimes adds [0,0,0])
            # to avoid confusing some renderers
            if mat.get('emissiveFactor') == [0, 0, 0]:
                del mat['emissiveFactor']

        # If no materials exist at all, create one
        if not gltf.get('materials'):
            gltf['materials'] = [{
                'name': 'helio_pbr',
                'pbrMetallicRoughness': {
                    'baseColorFactor': [1.0, 1.0, 1.0, 1.0],
                    'metallicFactor': metallic,
                    'roughnessFactor': roughness,
                },
                'doubleSided': True,
            }]

        # Re-encode JSON
        new_json = _json.dumps(gltf, separators=(',', ':')).encode('utf-8')
        # Pad to 4-byte alignment (GLB spec requires it)
        while len(new_json) % 4 != 0:
            new_json += b' '

        # Rebuild GLB binary
        new_total = 12 + 8 + len(new_json) + len(bin_chunk)
        header = struct.pack('<III', magic, version, new_total)
        json_hdr = struct.pack('<II', len(new_json), json_type)
        with open(glb_path, 'wb') as f:
            f.write(header + json_hdr + new_json + bin_chunk)
    except Exception as e:
        print(f"[HELIO Pro] GLB material fix warning: {e}")

