        # ── Full keyboard shortcut system ─────────────────────────────────────
        def _no_entry_focus(event=None):
            """Return False (block shortcut) when a text-entry widget has focus."""
            fw = self.focus_get()
            return isinstance(fw, (ctk.CTkEntry, tk.Entry, ctk.CTkTextbox, tk.Text))

        def _kbd_reprocess(e):
            if _no_entry_focus(): return
            if getattr(self, 'normals_proxy', None) is not None: self.run_processing()
        def _kbd_snapshot(e):
            if _no_entry_focus(): return
            self.export_highres_tiff()
        def _kbd_engine_fwd(e):
            if _no_entry_focus(): return
            idx = self.engines_list.index(self.render_engine.get()) if self.render_engine.get() in self.engines_list else 0
            self.render_engine.set(self.engines_list[(idx + 1) % len(self.engines_list)])
            self.on_engine_change(self.render_engine.get())
        def _kbd_engine_bwd(e):
            if _no_entry_focus(): return
            idx = self.engines_list.index(self.render_engine.get()) if self.render_engine.get() in self.engines_list else 0
            self.render_engine.set(self.engines_list[(idx - 1) % len(self.engines_list)])
            self.on_engine_change(self.render_engine.get())
        def _kbd_gif(e):
            if _no_entry_focus(): return
            self.export_sweep_gif()
        def _kbd_sweep(e):
            if _no_entry_focus(): return
            self.toggle_sweep()
        def _kbd_histogram(e):
            if _no_entry_focus(): return
            self.show_histogram()
        def _kbd_fit(e):
            if _no_entry_focus(): return
            self.zoom_scale = 1.0
            if hasattr(self, 'lbl_mag'): self.lbl_mag.configure(text="100%")
            self.update_main_view()
        def _kbd_shortcuts(e):
            self._show_shortcuts_overlay()
        def _kbd_undo_crop(e):
            if _no_entry_focus(): return
            self._clear_crop_handles()
        def _kbd_debug_toggle(e):
            global _HELIO_DEBUG
            _HELIO_DEBUG = not _HELIO_DEBUG
            suffix = " [DEBUG]"
            current = self.title()
            if _HELIO_DEBUG:
                if suffix not in current: self.title(current + suffix)
            else:
                self.title(current.replace(suffix, ""))

        self.bind("<r>",                 _kbd_reprocess)
        self.bind("<R>",                 _kbd_reprocess)
        self.bind("<s>",                 _kbd_snapshot)
        self.bind("<S>",                 _kbd_snapshot)
        self.bind("<e>",                 _kbd_engine_fwd)
        self.bind("<E>",                 _kbd_engine_bwd)
        self.bind("<g>",                 _kbd_gif)
        self.bind("<G>",                 _kbd_gif)
        self.bind("<a>",                 _kbd_sweep)
        self.bind("<A>",                 _kbd_sweep)
        self.bind("<h>",                 _kbd_histogram)
        self.bind("<H>",                 _kbd_histogram)
        self.bind("<f>",                 _kbd_fit)
        self.bind("<F>",                 _kbd_fit)
        self.bind("<question>",          _kbd_shortcuts)
        self.bind("<Control-Shift-D>", lambda e: self._run_debug_test())
        self.bind("<Control-z>",         _kbd_undo_crop)
        self.bind("<Meta-z>",            _kbd_undo_crop)   # macOS Cmd+Z
        self.bind("<Control-Z>",         _kbd_debug_toggle)
        self.bind("<Control-Shift-D>",   _kbd_debug_toggle)
