    def compute_ptm_relighting(self, c, u, v): return c[0]*u**2 + c[1]*v**2 + c[2]*u*v + c[3]*u + c[4]*v + c[5]
    def compute_hsh_relighting(self, c, u, v, z): return c[0] + c[1]*u + c[2]*v + c[3]*z + c[4]*u*v + c[5]*u*z + c[6]*v*z + c[7]*(u**2 - v**2) + c[8]*(3*z**2 - 1)

