        def _update_fair_preview(*_):
            inst = self.fair_institution_var.get().strip().replace(" ","_")
            obj  = self.object_id_var.get().strip().replace(" ","_") or "Object"
            solver = self.normal_engine.get().split()[0][:8]
            ts   = __import__("time").strftime("%Y%m%d")
            parts = [p for p in [inst, obj, solver, ts] if p]
            self._fair_preview_lbl.configure(text=" → " + "_".join(parts))
        self._fair_preview_lbl = ctk.CTkLabel(_fair_row, text=" → preview",
                                              font=("Arial", 8), text_color="#2a7a4a")
        self._fair_preview_lbl.pack(side="left", padx=4)
        self.fair_institution_var.trace_add("write", _update_fair_preview)
        self.object_id_var.trace_add("write", _update_fair_preview)

        # Object ID: auto-populates from metadata title (handled in _update_status_bar)
        self.normal_engine.trace_add("write", _update_fair_preview)
        self.flatten_illumination_var = tk.BooleanVar(value=False)
        chk_flat = ctk.CTkCheckBox(f_in, text="Auto-Flatten Falloff", variable=self.flatten_illumination_var, text_color="cyan")
        ToolTip(chk_flat, "Equalises uneven lighting falloff across the image caused by\n""vignetting or lamp distance variation.\n\n""Uses Multi-Scale Retinex (MSR): estimates and removes broad\n""illumination gradients while preserving surface texture.\n""Recommended for objects lit with a small or off-centre dome\n""where edges appear darker than the centre.\n""Has no effect on already-uniform illumination sets.")
        chk_norm = ctk.CTkCheckBox(f_in, text="Multi-Light Normalise", variable=self.multi_norm_var, text_color="cyan")
        ToolTip(chk_norm, "Equalises overall brightness between all captured images\n""by scaling each frame to the same median intensity.\n\n""Corrects for flash power drift, exposure inconsistency, or\n""slight variation between light positions in your dome.\n""Without this, brighter images bias the normal solver toward\n""the directions those lights illuminate from.\n""Safe to leave on for most captures.")
        chk_norm.pack(pady=2, padx=10, anchor="w")

        # Per-image CLAHE pre-processing before PS solve
        self.pre_clahe_var = tk.BooleanVar(value=False)
        chk_clahe = ctk.CTkCheckBox(f_in, text="Per-Image CLAHE (Raking Enhancement)",
                                     variable=self.pre_clahe_var, text_color="#f0c060")
        chk_clahe.pack(pady=2, padx=10, anchor="w")
        ToolTip(chk_clahe,
                "Applies CLAHE to each image individually before the PS solve.\n\n"
                "Faint drypoint scratches only cast a visible shadow in 1–2\n"
                "raking images. That shadow gets averaged away in the global\n"
                "solve unless each image's local contrast is first boosted.\n\n"
                "CLAHE enhances local contrast without changing global brightness,\n"
                "so the normal solver still receives a consistent stack.\n\n"
                "Best for: drypoint, dry-point, blind impressions (manuscripts).\n"
                "Clip 2–4, Tile 16 is a good starting point.")
        _clahe_row1 = ctk.CTkFrame(f_in, fg_color="#1a1a2a", corner_radius=4)
        _clahe_row1.pack(fill="x", padx=14, pady=(0, 4))

        _cr1 = ctk.CTkFrame(_clahe_row1, fg_color="transparent")
        _cr1.pack(fill="x", padx=8, pady=(6, 2))
        ctk.CTkLabel(_cr1, text="Clip Limit", font=("Arial", 11), width=80,
                     anchor="w", text_color="#f0c060").pack(side="left")
        self.pre_clahe_clip_var = tk.DoubleVar(value=2.0)
        _clahe_clip_lbl = ctk.CTkLabel(_cr1, text="2.0", font=("Arial", 11, "bold"),
                                        width=40, text_color="#ffffff")
        _clahe_clip_lbl.pack(side="right")
        ctk.CTkSlider(_cr1, from_=1.0, to=8.0, variable=self.pre_clahe_clip_var,
                      button_color="#f0c060", progress_color="#c09030",
                      command=lambda v: _clahe_clip_lbl.configure(text=f"{float(v):.1f}")
                      ).pack(side="left", fill="x", expand=True, padx=(4, 8))

        _cr2 = ctk.CTkFrame(_clahe_row1, fg_color="transparent")
        _cr2.pack(fill="x", padx=8, pady=(2, 6))
        ctk.CTkLabel(_cr2, text="Tile Size", font=("Arial", 11), width=80,
                     anchor="w", text_color="#f0c060").pack(side="left")
        self.pre_clahe_tile_var = tk.IntVar(value=16)
        _clahe_tile_lbl = ctk.CTkLabel(_cr2, text="16 px", font=("Arial", 11, "bold"),
                                        width=40, text_color="#ffffff")
        _clahe_tile_lbl.pack(side="right")
        ctk.CTkSlider(_cr2, from_=4, to=64, variable=self.pre_clahe_tile_var,
                      button_color="#f0c060", progress_color="#c09030",
                      command=lambda v: _clahe_tile_lbl.configure(text=f"{int(float(v))} px")
                      ).pack(side="left", fill="x", expand=True, padx=(4, 8))

        chk_align = ctk.CTkCheckBox(f_in, text="Auto-Align Images (Phase Corr.)",
                                    variable=self.auto_align_var, text_color="#a8c8e8")
        chk_align.pack(pady=2, padx=10, anchor="w")
        ToolTip(chk_align,
                "Corrects sub-pixel camera-shift between captures using\n"
                "FFT phase-correlation (illumination-invariant).\n"
                "Reference: median stack (albedo proxy).  Cap ±5 %% diagonal.\n"
                "Run 'Re-Align Images Now' below for a standalone report.")
        self._add_btn(f_in, "\U0001f527 Re-Align Images Now", self.realign_images_now,
                      "Phase-correlate all images against the median stack and\n"
                      "display a per-image shift report without re-processing.\n"
                      "Tick the checkbox above to apply on every process run.",
                      color="#1a3a5a", requires_data=True)
        chk_nf = ctk.CTkCheckBox(f_in, text="Near-Field Light Correction", variable=self.near_field_var, text_color="#e8d5a3")
        chk_nf.pack(pady=2, padx=10, anchor="w")
        ToolTip(chk_nf, "Corrects for the fact that lights on a small dome are NOT\n""infinitely far away — light intensity falls off with distance.\n\n""Without this correction, pixels near the edge of the object\n""(farther from dome lights) appear systematically darker,\n""biasing the normal calculation.\n""Enter your dome radius in mm below.\n""Only needed for domes smaller than ~400mm radius.")
        nf_row = ctk.CTkFrame(f_in, fg_color="transparent"); nf_row.pack(fill="x", padx=18, pady=(0,4))
        ctk.CTkLabel(nf_row, text="Dome radius (mm):", font=("Arial", 10), text_color="gray").pack(side="left")
        ctk.CTkEntry(nf_row, textvariable=self.dome_radius_var, width=70).pack(side="right")

        # [Metrological Stand Calibration removed]

        # ── Reference Flat Surface Correction ─────────────────────────────────
        ctk.CTkLabel(f_in, text="─── Reference Flat Correction ───",
                     font=("Arial", 9), text_color="#8899bb").pack(pady=(6,2))
        _btn_flat_ref = self._add_btn(f_in, "1F. Load Reference Flat Images",
                                      self.load_flat_reference_images,
                                      "Load blank flat-surface images captured with IDENTICAL lighting.\n"
                                      "PS normals of the flat reveal systematic distortions caused by\n"
                                      "light non-uniformity, brightness variation, and non-parallelism.\n"
                                      "These are subtracted from your object normals before integration.\n"
                                      "(Gaiani et al. 2025, Section 2.2C)",
                                      color="#1a3a1a", requires_data=False)
        self.lbl_flat_ref = ctk.CTkLabel(f_in, text="No flat reference loaded",
                                          font=("Arial", 9), text_color="#777")
        self.lbl_flat_ref.pack(pady=(0,2), padx=10, anchor="w")
        chk_flat_corr = ctk.CTkCheckBox(f_in, text="Apply flat-field normal correction",
                                         variable=self.flat_correction_var, text_color="#a8e8a8")
        chk_flat_corr.pack(pady=2, padx=10, anchor="w")
        ToolTip(chk_flat_corr,
                "Uses blank flat-surface images (loaded via 1F above) to measure\n"
                "the systematic distortion pattern your dome introduces to normals.\n"
                "This distortion field is then subtracted from your object normals\n"
                "before depth integration.\n\n"
                "Corrects for: light non-uniformity, beam non-parallelism,\n"
                "brightness falloff, and dome geometry asymmetry.\n"
                "Dramatically reduces the 'potato-chip' warp on flat objects.\n\n"
                "Requires: 1F flat reference images loaded first.\n"
                "Correction strength slider: 100% for matte surfaces,\n"
                "reduce for glazed/metallic objects.")
        _corr_row = ctk.CTkFrame(f_in, fg_color="transparent"); _corr_row.pack(fill="x", padx=18, pady=(0,4))
        ctk.CTkLabel(_corr_row, text="Correction strength:", font=("Arial", 10), text_color="gray").pack(side="left")
        ctk.CTkSlider(_corr_row, from_=0.0, to=1.0, variable=self.flat_corr_strength_var, width=90).pack(side="right", padx=4)
        ToolTip(_corr_row.winfo_children()[-1],
                "100% = full correction (matte surfaces).\n"
                "Reduce for partially specular surfaces where the flat reference\n"
                "may not perfectly model specular component.")

        # ── Depth correction (applied during processing) ─────────────────────
        _sep_corr = ctk.CTkLabel(f_in,
            text="─── Depth Correction (applied on Process) ───",
            font=("Arial", 9), text_color="#c8a84b")
        _sep_corr.pack(pady=(6,2))
        chk_parab = ctk.CTkCheckBox(f_in, text="✔  Parabolic Depth Correction",
                                     variable=self.parabolic_corr_var, text_color="#e8d5a3")
        chk_parab.pack(pady=2, padx=10, anchor="w")
        ToolTip(chk_parab,
                "Removes systematic bowl, dome or saddle warp from the depth map\n"
                "after Poisson integration — the most common cause of flat objects\n"
                "appearing to curve or dish in the 3D viewer.\n\n"
                "How it works: fits a 3×3 parabolic surface (ax²+by²+cxy+dx+ey+f)\n"
                "to the integrated depth and subtracts it. Fine surface micro-relief\n"
                "is completely unaffected — only the broad low-frequency warp is removed.\n\n"
                "✔  Tick before clicking Load Scans & Process (or before confirming\n"
                "   the Virtual Dome Calibrator / Sphere Sync) — correction bakes in\n"
                "   automatically. Re-process to apply after changing this setting.\n\n"
                "Best for: flat manuscripts, documents, leather bindings, coins.\n"
                "Reference: Gaiani et al. 2025, Heritage 8(4), Section 2.2C.")

        self._add_btn(f_in, "2. Load Scans & Process", lambda: self.load_data('plate'),
                      tip="Select your photometric stereo images (JPG / PNG / TIFF).\n\n"
                          "All pre-processing options ticked above (Flatten Falloff,\n"
                          "Multi-Light Normalise, Near-Field Correction, Flat-Field\n"
                          "Correction, Parabolic Depth Correction) are applied\n"
                          "automatically during this step.\n\n"
                          "If using the Virtual Dome Calibrator (1C) or Sphere Sync\n"
                          "(1B), processing fires automatically on Confirm —\n"
                          "you do not need to click this button separately.\n\n"
                          "Minimum 8 images recommended; 16–64 is ideal.",
                      color="#1a3a5a", requires_data=False)
        # Reprocess Crop Region button is in the Magnifier panel (right column, near zoom controls)
        # Progress bar is now above the main viewport — see center_frame row 2

        # ══ SESSION (collapsible, closed by default) ══════════════════════════
        _, f_sess = self._make_collapsible(left, "Session & Batch", color="#5dade2", start_open=False)
        sr = ctk.CTkFrame(f_sess, fg_color="transparent"); sr.pack(fill="x", padx=4, pady=2)
        _bs = ctk.CTkButton(sr, text="💾 Save Session", fg_color="#1a4a6b", command=self.save_session)
        _bs.pack(side="left", padx=3, expand=True, fill="x"); ToolTip(_bs, "Save full session as .helio project file.")
        _bl = ctk.CTkButton(sr, text="📂 Load Session", fg_color="#1a4a6b", command=self.load_session)
        _bl.pack(side="right", padx=3, expand=True, fill="x"); ToolTip(_bl, "Reload a saved .helio session.")
        self.lbl_session = ctk.CTkLabel(f_sess, text="No session loaded", font=("Arial", 10), text_color="gray")
        self.lbl_session.pack(pady=(0,4))
        ctk.CTkLabel(f_sess, text="🌙 Overnight Batch Processing",
                     font=("Arial", 11, "bold"), text_color="#e8a87c").pack(pady=(6,2))
        # Scan parent directory button
        _bscan_row = ctk.CTkFrame(f_sess, fg_color="transparent"); _bscan_row.pack(fill="x", padx=4, pady=2)
        _bscan = ctk.CTkButton(_bscan_row, text="📂 Scan Directory",
                                fg_color="#1a4a6b", command=self.batch_scan_directory)
        _bscan.pack(side="left", expand=True, fill="x", padx=(0,2))
        ToolTip(_bscan, "Choose a parent folder.\n"
                "HELIO scans for subfolders — each subfolder should contain\n"
                "your images for one object. A shared .lp light file in the\n"
                "parent folder is loaded automatically if present.")
        _bclear = ctk.CTkButton(_bscan_row, text="✕ Clear", fg_color="#3a1a1a",
                                 command=self.batch_clear, width=60)
        _bclear.pack(side="right")
        ToolTip(_bclear, "Clear the scanned folder list.")
        # Shared LP file option
        _blp_row = ctk.CTkFrame(f_sess, fg_color="transparent"); _blp_row.pack(fill="x", padx=4, pady=(2,0))
        ctk.CTkLabel(_blp_row, text="Shared .lp:", font=("Arial", 9),
                     text_color="#6a9aaa").pack(side="left")
        self._batch_lp_var = tk.StringVar(value="")
        self._batch_lp_lbl = ctk.CTkLabel(_blp_row, text="(none — auto-detect per folder)",
                                           font=("Arial", 8), text_color="gray")
        self._batch_lp_lbl.pack(side="left", padx=4)
        _blp_btn = ctk.CTkButton(_blp_row, text="Browse .lp", fg_color="#2a3a5a",
                                  height=22, width=70,
                                  command=self._batch_load_shared_lp)
        _blp_btn.pack(side="right")
        ToolTip(_blp_btn, "Load a shared light-position file (.lp / .dome / .txt)\n"
                "used for ALL folders in the batch. If a folder has its own\n"
                ".lp file, that folder's file takes priority.")

        # ── Chrome sphere calibration option ──────────────────────────────────
        _sphere_row = ctk.CTkFrame(f_sess, fg_color="#0a1a0a", corner_radius=4)
        _sphere_row.pack(fill="x", padx=6, pady=(2,4))
        ctk.CTkLabel(_sphere_row, text="  OR  ", font=("Arial", 8, "bold"),
                     text_color="#3a5a3a").pack(side="left")
        _sphere_btn = ctk.CTkButton(_sphere_row,
            text="🔮  Calibrate from Chrome Sphere",
            fg_color="#1a3a1a", hover_color="#2a5a2a",
            font=("Arial", 10, "bold"), height=28,
            command=self._batch_calibrate_from_sphere)
        _sphere_btn.pack(side="left", fill="x", expand=True, padx=4, pady=4)
        ToolTip(_sphere_btn,
            "Load a set of chrome sphere calibration images — the same\n"
            "sphere captured under each light of your dome.\n\n"
            "HELIO opens the precision sphere dialog where you draw a\n"
            "circle around the sphere. The extracted light vectors are\n"
            "used as the shared calibration for ALL batch folders.\n\n"
            "Use this when all your objects were shot under the same dome\n"
            "and you have a single sphere reference set.")
        self._batch_sphere_lbl = ctk.CTkLabel(_sphere_row, text="",
                                               font=("Arial", 8), text_color="#27ae60")
        self._batch_sphere_lbl.pack(side="right", padx=4)

        # ── RTI-style guided sphere ROI (recommended) ─────────────────────────
        _roi_frame = ctk.CTkFrame(f_sess, fg_color="#0a1a0a", corner_radius=4)
        _roi_frame.pack(fill="x", padx=6, pady=(0,2))
        ctk.CTkLabel(_roi_frame, text="  ⭐ Recommended: draw sphere region once",
                     font=("Arial", 9, "bold"), text_color="#5a9a6a").pack(
                     anchor="w", padx=8, pady=(6,2))
        _roi_btn = ctk.CTkButton(_roi_frame,
            text="✏️  Draw Sphere Region  (RTI-style)",
            fg_color="#1a3a1a", hover_color="#2a5a2a",
            font=("Arial", 10, "bold"), height=28,
            command=self._batch_draw_sphere_roi)
        _roi_btn.pack(fill="x", padx=6, pady=(0,2))
        self._batch_roi_lbl = ctk.CTkLabel(_roi_frame,
            text="(no ROI set — auto-detection will be used)",
            font=("Arial", 8), text_color="#4a6a4a")
        self._batch_roi_lbl.pack(anchor="w", padx=8, pady=(0,6))
        ToolTip(_roi_btn,
            "RTI Builder approach — the most reliable sphere method.\n\n"
            "Shows the median image from your first scanned folder.\n"
            "Draw a rectangle loosely around the chrome sphere.\n"
            "HELIO detects the sphere boundary within that ROI only\n"
            "and applies it to every batch folder.\n\n"
            "Use this when:\n"
            "  • Sphere is small or in a corner\n"
            "  • Images are dark or cluttered\n"
            "  • Auto-detection gives wrong results\n\n"
            "CHI minimum standard: sphere must be >= 200px diameter.")

        # ── Auto-detect fallback ───────────────────────────────────────────────
        self._batch_auto_sphere_var = tk.BooleanVar(value=True)
        _auto_row = ctk.CTkFrame(f_sess, fg_color="transparent")
        _auto_row.pack(fill="x", padx=6, pady=(0,2))
        _auto_chk = ctk.CTkCheckBox(_auto_row,
            text="🔍 Fallback: auto-detect sphere",
            variable=self._batch_auto_sphere_var,
            font=("Arial", 10), text_color="#a0c8a0")
        _auto_chk.pack(side="left", padx=4)
        ToolTip(_auto_chk,
            "If no ROI is drawn and no sphere matrix is loaded,\n"
            "HELIO attempts automatic sphere detection.\n\n"
            "Works well when sphere is >= 200px diameter.\n"
            "Unreliable for tiny spheres (< 5% of frame width).")

        # ── PyTorch Deep PS fallback option ───────────────────────────────────
        self._batch_deepps_fallback_var = tk.BooleanVar(value=True)
        _dps_row = ctk.CTkFrame(f_sess, fg_color="transparent")
        _dps_row.pack(fill="x", padx=6, pady=(0,4))
        _dps_chk = ctk.CTkCheckBox(_dps_row,
            text="🧠 Deep PS fallback (no calib needed)",
            variable=self._batch_deepps_fallback_var,
            font=("Arial", 10), text_color="#a0a0c8")
        _dps_chk.pack(side="left", padx=4)
        ToolTip(_dps_chk,
            "When ticked, if a folder has no .lp file, no sphere detected,\n"
            "and no shared calibration, HELIO uses PyTorch Deep PS — a neural\n"
            "network solver that estimates light directions automatically from\n"
            "the image stack itself.\n\n"
            "Slower than calibrated solving (~2-4min per object) but requires\n"
            "zero calibration data. Ideal for overnight runs on mixed batches.\n\n"
            "When unticked, uncalibrated PCA is used instead (faster, less accurate).")

        # Queue status label
        self.lbl_batch = ctk.CTkLabel(f_sess, text="No folders scanned yet",
                                       font=("Arial", 10), text_color="gray")
        self.lbl_batch.pack(pady=(4,2))
        # Run button
        _brun = ctk.CTkButton(f_sess, text="▶  Configure Exports & Run",
                               fg_color="#1a6b3a", hover_color="#2a9b4a",
                               font=("Arial", 11, "bold"), height=34,
                               command=self.batch_configure_and_run)
        _brun.pack(fill="x", padx=6, pady=(2,6))
        ToolTip(_brun, "Opens the export picker — tick which outputs you want\n"
                "for every object, then start the overnight run.")

        # ── Welcome Guide button ──────────────────────────────────────────────
        _wg_row = ctk.CTkFrame(f_sess, fg_color="transparent"); _wg_row.pack(fill="x", padx=4, pady=(2,6))
        _btn_welcome = ctk.CTkButton(_wg_row, text="📖  Getting Started Guide",
                                      fg_color="#1a2e1a", hover_color="#2c4a2c",
                                      font=("Arial",10), height=24,
                                      command=self.show_welcome_wizard)
        _btn_welcome.pack(fill="x", padx=4)
        ToolTip(_btn_welcome, "Re-open the interactive Getting Started wizard.\nWalks through loading, processing, engines, metrology, and export in 6 steps.")

        # ══ 2. COMPUTE ENGINE (collapsible) ═══════════════════════════════════
        _, f_ai = self._make_collapsible(left, "2. Compute Engine", color="#f39c12", start_open=True)
        opt_n_eng = ctk.CTkOptionMenu(f_ai, values=[
            "PyTorch Deep PS",
            "Linear Least Squares",
            "Robust Least Squares (Shiny Metal)",
            "IRLS (Metallic/Specular)",
            "Iterative Specular Separation",
            "Shadow-Rejection LS",
            "Near-Field Attenuation",
            "Uncalibrated PCA",
        ], variable=self.normal_engine)
        opt_n_eng.pack(pady=4, fill="x", padx=8); ToolTip(opt_n_eng, "Select the normal solver algorithm.\nLinear LLS = fast, good for matte objects.\nRobust = handles some specularity.\nShadow-Rejection = excludes shadow frames per-pixel (best for hard shadows).\nNear-Field = small dome correction.")
        opt_d_eng = ctk.CTkOptionMenu(f_ai, values=[
            "Fast Poisson (FFT)",
            "Simchony DCT",
            "PyTorch L1 Edge-Preserving",
            "Confidence-Weighted Poisson",
            "Multi-Scale Integration",
            "Gradient-Smoothed Poisson",
            "Directional Integration",
        ], variable=self.depth_engine)
        opt_d_eng.pack(pady=4, fill="x", padx=8); ToolTip(opt_d_eng,
            "Select the depth integration algorithm.\n\n"
            "Fast Poisson (FFT)       — Default. Fast, reliable for most objects.\n"
            "Simchony DCT             — Cosine-transform integration, good for smooth surfaces.\n"
            "PyTorch L1 Edge-Preserving — Preserves sharp depth edges, slower.\n"
            "Confidence-Weighted Poisson — Reduces specular hotspot depth distortion.\n"
            "Multi-Scale Integration  — Best for raised objects on curved substrate.\n"
            "Gradient-Smoothed Poisson — Reduces depth drift on flat areas (4/8-light domes).\n"
            "                           Uses albedo edges to preserve inscriptions and marks.\n"
            "Directional Integration  — Integrates normals along X only, Y only, then averages.\n"
            "                           Amplifies features running perpendicular to each axis.\n"
            "                           Best for faint drypoint scratches and ruling lines.")

        # ── PyTorch SVD acceleration checkbox ────────────────────────────────
        _torch_row = ctk.CTkFrame(f_ai, fg_color="transparent"); _torch_row.pack(fill="x", padx=8, pady=(2,0))
        _torch_chk = ctk.CTkCheckBox(_torch_row, text="GPU-Accelerated SVD (Apple Silicon/CUDA)",
                                     variable=self.pytorch_pca_var, font=("Arial", 10),
                                     text_color="#7dd4f8", width=20)
        _torch_chk.pack(side="left")
        ToolTip(_torch_chk, "When enabled, uses PyTorch torch.linalg.svd for the\n"
                "Uncalibrated PCA normal solver — 3-5x faster on Apple Silicon (MPS)\n"
                "and NVIDIA GPUs (CUDA) compared to NumPy SVD.\n"
                "Falls back to NumPy automatically if PyTorch is unavailable.")

        # Shadow rejection threshold (shown when Shadow-Rejection LS is selected)
        _sr_frame = ctk.CTkFrame(f_ai, fg_color="transparent"); _sr_frame.pack(fill="x", padx=8, pady=(0,2))
        ctk.CTkLabel(_sr_frame, text="Shadow Threshold", font=("Arial",10), text_color="gray").pack(side="left")
        _sr_sl = ctk.CTkSlider(_sr_frame, from_=5, to=40, number_of_steps=35, variable=self.shadow_thresh_var, width=100)
        _sr_sl.pack(side="right", padx=4)
        ToolTip(_sr_sl, "Pixel intensity below which a frame is treated as 'in shadow' for that pixel.\nOnly used by Shadow-Rejection LS solver.\n12 = good default. Higher = reject more frames as shadow.")
        ctk.CTkLabel(f_ai, text="Pre-Integration Smoothing", font=("Arial", 11), anchor="w").pack(fill="x", padx=8, pady=(4,0))
        self.depth_smooth_var = tk.IntVar(value=0)
        _sl_smooth = ctk.CTkSlider(f_ai, from_=0, to=10, number_of_steps=10, variable=self.depth_smooth_var)
        _sl_smooth.pack(fill="x", padx=8, pady=(2,4)); ToolTip(_sl_smooth, "Bilateral smoothing on normals before depth integration (0=off).")
        _aw=ctk.CTkFrame(f_ai,fg_color="transparent"); _aw.pack(fill="x",padx=8,pady=(2,0))
        ctk.CTkLabel(_aw,text="Adaptive Light Weight",font=("Arial",10),text_color="gray").pack(side="left")
        _aws=ctk.CTkSlider(_aw,from_=0.,to=1.,variable=self.adaptive_light_var,width=100)
        _aws.pack(side="right",padx=4)
        ToolTip(_aws,"Down-weights near-grazing lights before the normal solver.\n\n"
                "0 = all lights equal (default).\n"
                "0.5 = lights below ~25 deg get half weight.\n"
                "1.0 = lights below 10 deg near-zero weight.\n\n"
                "Best for rough stone, uneven parchment, thick leather.\n"
                "Leave at 0 for coins, smooth ceramics, flat engravings.")
        btn_recalc = ctk.CTkButton(f_ai, text="↻ Recalculate Depth", fg_color="#1a6b3a", command=self.recalculate_depth)
        btn_recalc.pack(fill="x", padx=8, pady=(0,2)); ToolTip(btn_recalc, "Re-run depth integration with current settings.")
        # Iterative normal refinement
        _ir_row = ctk.CTkFrame(f_ai, fg_color="transparent"); _ir_row.pack(fill="x", padx=8, pady=(2,2))
        ctk.CTkLabel(_ir_row, text="Iterations:", font=("Arial",10), text_color="gray").pack(side="left")
        ctk.CTkOptionMenu(_ir_row, values=["2","3","4","6","8"], width=58,
                          command=lambda v: self.iter_refine_iters.set(int(v))).pack(side="left", padx=4)
        ctk.CTkLabel(_ir_row, text="PS:", font=("Arial",10), text_color="gray").pack(side="left", padx=(4,0))
        _ps_sl = ctk.CTkSlider(_ir_row, from_=0.5, to=0.97, variable=self.iter_ps_weight_var, width=70)
        _ps_sl.pack(side="right", padx=2)
        ToolTip(_ps_sl, "PS weight (0.85 = preserve 85% PS detail, blend 15% depth-gradient normals).")
        btn_iter = ctk.CTkButton(f_ai, text="🔁 Iterative Normal Refine", fg_color="#2a4a8a",
                                  command=self.recalculate_normals_iterative)
        btn_iter.pack(fill="x", padx=8, pady=(0,4)); ToolTip(btn_iter, "Enforce integrability of PS normals via alternating FC integration + blending.\nReduces non-integrable noise from specularity/shadows → cleaner mesh.\nDoes NOT modify stored data — only recomputes depth and refreshes view.")
        self.requires_data_widgets.extend([btn_recalc, btn_iter])
        self._add_btn(f_ai, "Self-Supervise Model", self.open_training_window, "Train a custom AI network.", requires_data=False)
        self._add_btn(f_ai, "Batch Train Master AI", self.open_master_training_window, "Train master network.", requires_data=False)

        self.lbl_suggestion = ctk.CTkLabel(left, text="", text_color="yellow", wraplength=300)
        self.lbl_suggestion.pack_forget()  # hidden until there's content to show

        # ══ 3. LIGHTING CONTROLS (collapsible) ════════════════════════════════
        _, dome_f = self._make_collapsible(left, "3. Lighting Controls", color="#f39c12", start_open=True)

        # ══ ANALYSIS & QC (collapsible) ═══════════════════════════════════════
        _, f_qc = self._make_collapsible(left, "Analysis & QC", color="#a29bfe", start_open=False)
        _btn_mae = ctk.CTkButton(f_qc, text="📐 Normal Map MAE vs Reference",
                                  fg_color="#3a2a6b", command=self.compare_normal_maps_mae)
        _btn_mae.pack(fill="x", padx=8, pady=(4,2))
        ToolTip(_btn_mae, "Load a reference normal map (PNG/TIF from photogrammetry,\n"
                "scanner, or another processing pass) and compute the Mean\n"
                "Angular Error (MAE) between it and the current PS normals.\n"
                "Displays a heatmap and frequency-split statistics.\n\n"
                "Based on Laurent et al. 2025 (J. Cultural Heritage), Tables 1–2.\n"
                "Typical values: PS vs Photogrammetry ≈ 7–20° overall,\n"
                "Low-freq component ≈ 2° with good calibration.")
        _btn_lf  = ctk.CTkButton(f_qc, text="🔬 Low-Frequency Bias Diagnostic",
                                  fg_color="#2a3a6b", command=self.analyse_calibration_bias)
        _btn_lf.pack(fill="x", padx=8, pady=(2,2))
        ToolTip(_btn_lf, "Isolates the low-frequency component of the current PS normals\n"
                "using a Gaussian LP filter and compares against the photogrammetry\n"
                "mesh normal field.\n\n"
                "Key finding (Laurent et al. 2025): poorly calibrated PS diverges\n"
                "at low frequencies (calibration bowl), not at high frequencies.\n"
                "A low-freq MAE < 3° indicates good calibration quality.\n"
                "Reports LP-MAE, HP-MAE, and saves diagnostic images.")
        # Gaussian sigma for LP/HP split
        _sig_row = ctk.CTkFrame(f_qc, fg_color="transparent"); _sig_row.pack(fill="x", padx=8, pady=(2,6))
        ctk.CTkLabel(_sig_row, text="LP σ (px):", font=("Arial",10), text_color="gray").pack(side="left")
        self.qc_lp_sigma_var = tk.IntVar(value=10)
        ctk.CTkSlider(_sig_row, from_=5, to=50, number_of_steps=45, variable=self.qc_lp_sigma_var, width=90).pack(side="right")
        ToolTip(_sig_row.winfo_children()[-1], "Gaussian sigma for LP/HP normal map split.\n"
                "10 px matches the 10×10 Gaussian filter used in Laurent et al. 2025.")
        self.requires_data_widgets.extend([_btn_mae, _btn_lf])

        # ── Top row: sweep + GIF + Best Raking ────────────────────────────────
        d_top = ctk.CTkFrame(dome_f, fg_color="transparent"); d_top.pack(fill="x", padx=6)
        self.btn_sweep = ctk.CTkButton(d_top, text="▶ Auto-Sweep", width=110, fg_color="#e67e22", command=self.toggle_sweep)
        self.btn_sweep.pack(side="left", padx=3, pady=2); self.requires_data_widgets.append(self.btn_sweep)
        ToolTip(self.btn_sweep, "Animate light in a circle around the object.")
        self.btn_gif = ctk.CTkButton(d_top, text="GIF", width=44, fg_color="#4a6984", command=self.export_sweep_gif)
        self.btn_gif.pack(side="left", padx=2, pady=2); self.requires_data_widgets.append(self.btn_gif)
        ToolTip(self.btn_gif, "Export light sweep as animated GIF.")
        self.btn_raking = ctk.CTkButton(d_top, text="🔍 Best Raking", width=110, fg_color="#6c3483", height=28, command=self.find_best_raking_angle)
        self.btn_raking.pack(side="right", padx=3, pady=2); self.requires_data_widgets.append(self.btn_raking)
        ToolTip(self.btn_raking, "Auto-scan all captured light angles and find the one with maximum surface contrast.")

        # Sweep speed
        spd_row = ctk.CTkFrame(dome_f, fg_color="transparent"); spd_row.pack(fill="x", padx=8, pady=(0,2))
        ctk.CTkLabel(spd_row, text="Sweep speed:", font=("Arial",10), text_color="gray").pack(side="left")
        self._sweep_spd_var = tk.DoubleVar(value=1.0)
