        ToolTip(spd_row.winfo_children()[1], "Rotation speed for the auto-sweep animation.")

        # ── Dome canvas — 150×150px (15% smaller than 176 for responsiveness) ──
        # cx=cy=75, r=53 → N/S/E/W labels at r+11=64, well within 75px half-width
        DOME_SZ = 150; DOME_CX = 75; DOME_CY = 75; DOME_R = 53
        self._dome_cx = DOME_CX; self._dome_cy = DOME_CY; self._dome_r = DOME_R
        _DOME_BG = "#1c1f26"

        dome_canvas_f = ctk.CTkFrame(dome_f, fg_color="transparent"); dome_canvas_f.pack(pady=1)
        self.canvas = tk.Canvas(dome_canvas_f, width=DOME_SZ, height=DOME_SZ,
                                bg=_DOME_BG, highlightthickness=0, bd=0)
        self.canvas.pack()

        def _draw_dome_static():
            import math as _m
            c = self.canvas; cx = DOME_CX; cy = DOME_CY; r = DOME_R
            c.create_oval(cx-r, cy-r, cx+r, cy+r, outline="#3a8fbf", width=2)
            for elev_deg, col, dash in [(30, "#2a5a7a", (4,3)), (60, "#1e3d55", (3,4))]:
                rp = int(r * _m.cos(_m.radians(elev_deg)))
                c.create_oval(cx-rp, cy-rp, cx+rp, cy+rp, outline=col, dash=dash, width=1)
            c.create_oval(cx-3, cy-3, cx+3, cy+3, outline="#2a9", fill=_DOME_BG, width=1)
            for az_deg in range(0, 360, 45):
                is_card = az_deg % 90 == 0; tick_len = 8 if is_card else 4
                rad = _m.radians(az_deg)
                ox = cx + r * _m.sin(rad); oy = cy - r * _m.cos(rad)
                ix = cx + (r - tick_len) * _m.sin(rad); iy = cy - (r - tick_len) * _m.cos(rad)
                c.create_line(ix, iy, ox, oy, fill="#4a9fbf" if is_card else "#1e4a6a", width=2 if is_card else 1)
            for az_d, lbl in [(0,"N"),(90,"E"),(180,"S"),(270,"W")]:
                rad = _m.radians(az_d); lr = r + 11
                c.create_text(cx + lr*_m.sin(rad), cy - lr*_m.cos(rad),
                              text=lbl, fill="#5dade2", font=("Arial",7,"bold"))

        _draw_dome_static()

        # Captured light dots — always shown, drawn before the light point
        self._dome_light_dots = []
        self._show_captured_lights = tk.BooleanVar(value=True)
        # _el_var kept for backend compatibility
        self._el_var = tk.DoubleVar(value=45.0)

        self.light_point = self.canvas.create_oval(
            DOME_CX-5, DOME_CY-5, DOME_CX+5, DOME_CY+5,
            fill="#f9e547", outline="white", width=2)

        self.canvas.bind("<ButtonPress-1>", self.start_dome_interaction)
        self.canvas.bind("<B1-Motion>",     self.update_light)
        self.canvas.bind("<ButtonRelease-1>", self.stop_interaction)
        ToolTip(self.canvas, "Click & drag to position the virtual light.\nYellow dot = light direction.\nInner rings = 30° and 60° elevation.\nBlue dots = your dataset's captured light positions.")

        # ── Hemisphere readout + typed entry (RTI Builder-style) ─────────────
