        self._compare_eng_menu = ctk.CTkOptionMenu(_cmp_row,
            values=self.engines_list,
            variable=self._compare_engine,
            width=140, font=("Arial", 9),
            command=lambda _: self.update_main_view() if self._compare_active else None)
        self._compare_eng_menu.pack(side="left", padx=(0,4))
        ToolTip(self._compare_eng_menu, "The render engine shown on the RIGHT side of the A/B wipe.")

        # Wipe position slider — drag to reposition the split line
        _cmp_slider_row = ctk.CTkFrame(f_rend, fg_color="transparent")
