        opt_vis.pack(pady=4, fill="x", padx=8); self.requires_data_widgets.append(opt_vis); ToolTip(opt_vis, "Select visual layer.")
        self.conf_frame = ctk.CTkFrame(f_rend, fg_color="transparent")
        ctk.CTkLabel(self.conf_frame, text="Confidence Map Settings:", text_color="cyan", font=("Arial", 11)).pack(anchor="w", padx=8)
        c_opts = ctk.CTkFrame(self.conf_frame, fg_color="transparent"); c_opts.pack(fill="x", padx=8, pady=2)
        opt_conf_col = ctk.CTkOptionMenu(c_opts, values=["Red", "Green", "Blue", "Yellow", "Cyan", "Magenta"], variable=self.conf_color, width=100, command=self.refresh_all); opt_conf_col.pack(side="left", padx=2); ToolTip(opt_conf_col, "Highlight colour.")
        opt_conf_blend = ctk.CTkOptionMenu(c_opts, values=["Overlay", "Multiply", "Additive"], variable=self.conf_blend, width=100, command=self.refresh_all); opt_conf_blend.pack(side="left", padx=2)
        ToolTip(opt_conf_blend, "Blend mode for the confidence overlay.\nOverlay = balanced; Multiply = darkens low-confidence zones; Additive = highlights them.")
        sl_conf_op = ctk.CTkSlider(self.conf_frame, from_=0.0, to=1.0, variable=self.conf_opacity, command=self.refresh_all); sl_conf_op.pack(fill="x", padx=8, pady=4)
        ToolTip(sl_conf_op, "Opacity of the confidence map overlay.\n0 = invisible, 1 = fully opaque.")
        ctk.CTkLabel(self.conf_frame, text="Shadow Cutoff", font=("Arial", 11), anchor="w").pack(fill="x", padx=8)
        _sl_shadow_conf = ctk.CTkSlider(self.conf_frame, from_=0, to=100, number_of_steps=100, variable=self.conf_shadow_var, command=self.refresh_all); _sl_shadow_conf.pack(fill="x", padx=8, pady=(2,4))
        ToolTip(_sl_shadow_conf, "Pixels darker than this value are flagged as under-exposed / shadowed.\nFlagged pixels are highlighted by the confidence overlay.")
        ctk.CTkLabel(self.conf_frame, text="Highlight Cutoff", font=("Arial", 11), anchor="w").pack(fill="x", padx=8)
        _sl_hi_conf = ctk.CTkSlider(self.conf_frame, from_=150, to=255, number_of_steps=105, variable=self.conf_highlight_var, command=self.refresh_all); _sl_hi_conf.pack(fill="x", padx=8, pady=(2,4))
        ToolTip(_sl_hi_conf, "Pixels brighter than this value are flagged as over-exposed / specular.\nFlagged pixels are highlighted by the confidence overlay.")
        _chk_conf_mask = ctk.CTkCheckBox(self.conf_frame, text="Mask Output by Confidence", variable=self.conf_mask_var, command=self.refresh_all, text_color="orange"); _chk_conf_mask.pack(anchor="w", padx=8, pady=(2,4))
        ToolTip(_chk_conf_mask, "Mask the render output — pixels outside the confidence range are blacked out.\nUseful for identifying which surface areas have reliable photometric data.")

        ctk.CTkLabel(left, text="Analysis Adjustments", text_color="#a9cce3",
                     font=("Arial", 12, "bold")).pack(pady=(4, 0), padx=10, anchor="w")
        self.slider_panel = ctk.CTkFrame(left, fg_color="transparent")
        self.slider_panel.pack(fill="x", expand=False, pady=3)
        self.sliders, self.slider_widgets = {}, {}
        slider_configs = [
            ("Exposure / Gain",         "gain",             0.1, 5.0,  0.15, "Intensity multiplier for the current render engine.\nDefault 0.15 for Standard PBR — raise for metallic/raised objects."),
            ("Brightness",              "bright",           0.4, 1.8,  1.0,  "Overall brightness adjustment."),
            ("Contrast",                "contrast",         0,   50,   0,    "Contrast enhancement (0=none)."),
            ("Gamma Correction",        "gamma",            0.1, 3.0,  1.0,  "Gamma curve. 1.0=linear. <1=lighter midtones. >1=darker."),
            ("Micro-Detail Boost",      "micro",            0.0, 2.0,  0.0,  "Adds texture detail from the albedo."),
            ("Roughness Opacity",       "rough_opacity",    0.0, 1.0,  0.5,  "Blends the roughness map into the output (Roughness Fusion mode)."),
            ("HS Altitude",             "hs_alt",           5,   90,   45,   "Sun elevation angle for hillshade rendering (degrees from horizon)."),
            ("HS Azimuth",              "hs_azi",           0,   360,  315,  "Sun compass direction for hillshade (0=North, 90=East, 315=NW)."),
            ("HS Z-Factor",             "hs_z",             0.1, 10.0, 1.0,  "Vertical exaggeration factor for hillshade depth."),
            ("HS Ambient",              "hs_amb",           0.0, 1.0,  0.3,  "Minimum brightness for hillshade (prevents pure black shadows)."),
            # Shape Index
            ("Shape Pre-Smooth",        "shape_smooth",     0.0, 8.0,  1.5,  "Gaussian pre-smoothing before curvature computation.\nHigher = smoother but loses fine detail."),
            # Bilateral Normal Sharpening
            ("Bilateral Diameter",      "bil_d",            3,   21,   9,    "Neighbourhood diameter for bilateral filter.\nLarger = stronger smoothing on flat areas."),
            ("Bilateral Sigma",         "bil_sc",           0.01,0.5,  0.1,  "Edge-sensitivity of bilateral filter.\nLow = only blur smooth areas. High = blur across edges too."),
            # Retinex
            ("Local Contrast Scale S", "ret_scale_s",  1,  40,  8,   "Primary neighbourhood size as % of image height.\n1%=fine detail, 20%=broad illumination. Drag left for finer ink contrast."),
            ("Local Contrast Scale M",  "ret_scale_m",  5,  80, 30,  "Secondary neighbourhood size (% of image height). Blended with Scale S.\nKeep > Scale S. Larger values remove broader illumination variation."),
            ("S/M Blend",               "ret_scale_l",  0, 500, 250, "Blend between Scale S (0) and Scale M (500).\n0 = use Scale S only (fine).  500 = use Scale M only (broad)."),
            # ── Raking Composite ──────────────────────────────────────────────
            ("Raking Elevation°",       "rk_elevation", 5,  45,  20,  "Elevation of raking lights in degrees above horizon.\n5°=extreme grazing (faintest marks). 20°=standard. 45°=soft diffuse."),
            ("No. of Directions",       "rk_n_dirs",    2,   8,   4,  "Number of light directions evenly around 360°.\n2=east+west only. 4=cardinal. 8=maximum coverage (smoothest)."),
            # ── SVF ──────────────────────────────────────────────────────────
            # ── SVF (T-1: physical unit guidance in tooltip) ────────────────
            ("SVF Search Radius",     "svf_radius",  5,  200, 20,
             "Sky-View Factor search radius in pixels.\n"
             "Calibrate XY scale first (Metrology) for mm-accurate results.\n"
             "At 300 dpi (0.085 mm/px): 20 px ≈ 1.7 mm radius.\n"
             "For inscription/mark analysis (1-5 mm): use 10-60 px.\n"
             "For parchment buckle (10-50 mm): use 120-600 px."),
            ("SVF Directions",        "svf_dirs",    4,   32, 16,
             "Number of search directions for SVF computation.\n"
             "8 = fast. 16 = standard. 32 = highest quality."),
            # ── Openness ──────────────────────────────────────────────────────
            ("Openness Radius",       "op_radius",   5,  200, 20,
             "Search radius for Openness in pixels.\n"
             "Physical scale same as SVF — calibrate first.\n"
             "Smaller = fine features. Larger = broader terrain."),
            ("Openness Min Elev\u00b0",    "op_elev",     1,   45, 10,
             "Minimum elevation angle threshold for Openness.\nLower = more sensitive to shallow slopes."),
            # ── MSRM (T-2: expanded range + physical guidance) ───────────────
            ("MSRM Min Scale",        "msrm_min",    1,   20,  1,
             "Minimum feature scale (px) for Multi-Scale Relief Model.\n"
             "Set to ~half the width of the finest features to detect.\n"
             "Hairline scratches (1-3 px): use 1-2. Strokes (5-15 px): use 3-6."),
            ("MSRM Max Scale",        "msrm_max",    2,   60,  5,
             "Maximum feature scale for MSRM.\n"
             "Set to ~2x the broadest features to detect.\n"
             "Manuscript drypoint (up to 30 px): use 15-30. Creases: use 30-60."),
            # ── SLRM ──────────────────────────────────────────────────────────
            ("SLRM Radius",           "slrm_radius", 5,  100, 20, "Simple Local Relief Model search radius.\nControls the reference plane size.\n10-30 = good for manuscript work."),
            # ── Local Dominance ───────────────────────────────────────────────
            ("LD Radius",             "ld_radius",   5,  100, 20, "Local Dominance search radius in cells."),
            ("LD Min Elevation°",     "ld_elev",     5,   75, 35, "Minimum elevation angle for Local Dominance.\n35° = standard. Lower = more sensitive to shallow slopes."),
            # ── Shape Index ───────────────────────────────────────────────────
            ("Shape Sigma",           "si_sigma",  0.5,   8, 1.5, "Gaussian smoothing sigma for Shape Index computation.\nSmaller=fine curvature detail. Larger=macro shape."),
            # ── AO / HBAO ─────────────────────────────────────────────────────
            ("AO Search Radius",      "ao_radius",  5,  100, 20, "Ambient occlusion search radius in cells.\nSmaller=local contact shadows. Larger=broader shadowing."),
            ("AO Directions",         "ao_dirs",    4,   32, 16, "Number of AO sample directions.\n8=fast. 16=standard. 32=highest quality."),
            ("AO Edge Blend",         "ao_blend_e",0.0, 1.0, 0.5, "Blend between AO (0) and edge detection (1).\n0.5=balanced mix."),
            # Diffuse Gain (RTI-style)
            ("Diffuse Gain Strength", "dg_strength",0.5, 8.0, 2.0, "Main gain applied to the Lambertian (N·L) diffuse signal.\n2×=standard. 4-6×=strong detail enhancement for paper/parchment.\nBrings out fine surface texture like RTI diffuse enhancement mode.\nHigher values make shallow features much more visible."),
            ("Diffuse Gamma",         "dg_gamma",  0.2, 2.0, 0.7, "Gamma applied after gain. <1.0 = lift shadows (reveal fine marks).\n0.4-0.7 = aggressive shadow lift (good for faint stylus marks).\n1.0 = linear. >1.0 = darken (not usually useful here)."),
            ("Specular Suppress",     "dg_spec",   0.0, 1.0, 0.3, "Subtracts estimated specular contribution before gain.\n0=none. 0.3=moderate (good for semi-gloss paper).\n0.8-1.0=strong (use for vellum or glossy leather).\nPrevents highlight burn-out at high Diffuse Gain values."),
            # RTI Specular Enhancement sliders
            ("RTI Spec Coefficient",  "rti_spec_coeff",  0.2, 5.0, 1.5,
             "Per-pixel specular amplification coefficient.\n"
             "Equivalent to RTI Viewer's 'Specularity Enhancement' level.\n"
             "1.0 = no change. 2–3 = moderate boost (good for ink on parchment).\n"
             "4–5 = strong (use for embossing, seals, metallic surfaces)."),
            ("RTI Spec Floor",        "rti_spec_floor",  0.0, 0.5, 0.05,
             "Minimum specular response threshold — values below this are suppressed.\n"
             "Raise to 0.1–0.2 to suppress low-frequency noise before amplification.\n"
             "0.0 = amplify everything (may raise noise floor)."),
            ("RTI Spec/Diffuse Blend","rti_spec_blend",  0.0, 1.0, 0.6,
             "Balance between specular-enhanced and diffuse components.\n"
             "0.0 = pure diffuse (no specular amplification).\n"
             "0.6 = moderate blend — recommended starting point.\n"
             "1.0 = specular-only output (very high contrast on highlights)."),
            # RTI Image USM sliders
            ("RTI USM Sigma",         "rti_usm_sigma",   0.5, 8.0, 2.0,
             "Unsharp mask blur radius (sigma in pixels).\n"
             "Small (0.5–1.5): sharpens fine scratches and inscription strokes.\n"
             "Medium (2–4): brings out mid-scale surface texture.\n"
             "Large (5–8): enhances broad toolmark patterns.\n"
             "Applied in RTI re-lit image space, not in normal space."),
            ("RTI USM Amount",        "rti_usm_amount",  0.1, 5.0, 1.5,
             "Unsharp mask strength multiplier.\n"
             "1.0 = moderate sharpening. 2–3 = strong.\n"
             "Higher values increase noise — use RTI USM Threshold to control.\n"
             "RTI Viewer equivalent: 'Image Enhancement' sharpness."),
            ("RTI USM Threshold",     "rti_usm_thresh",  0.0, 0.3, 0.0,
             "Minimum edge contrast required before sharpening is applied.\n"
             "0.0 = sharpen everything including noise.\n"
             "0.05–0.1 = only sharpen features above this contrast level.\n"
             "Raises this if sharpening is amplifying background noise."),
            # Normal Residual
            ("Detail Scale %",     "nr_scale",  0.5,  20.0,  5.0, "Smoothing radius as % of image height.\n0.5%=finest micro-detail only. 5%=standard scratches & toolmarks.\n15%=broad texture. Controls what is REMOVED before showing residual.\nStart at 5 for stylus marks, lower for hairline scratches."),
            ("Residual Gain",      "nr_gain",   0.5,   5.0,  1.5, "Amplify the residual signal.\n1.0=neutral. 2-3=strong amplification for very faint marks.\nToo high will amplify noise — lower Detail Scale first."),
            ("Output Mode (0/1/2)", "nr_mode",   0,     2,    0,   "Drag to select output mode:\n\n0 = Greyscale (best for scratches — contrast centred at mid-grey)\n1 = False-colour: red=raised, blue=incised/pressed, grey=flat\n2 = Absolute value: all relief bright regardless of direction\n\nFor the Boleyn inscription: start with mode 0.\nUse mode 1 to distinguish pressed marks from raised ones."),
            # ── Ambient Occlusion group (AO / HBAO / AO Edge engines) ─────────
            ("AO Radius",               "ao_radius",        0.01,0.5,  0.08, "Sampling radius for AO hemisphere (normalised 0–1)."),
            ("AO Strength",             "ao_strength",      0.1, 5.0,  1.5,  "Multiplier for the computed occlusion factor."),
            ("AO Directions",           "ao_dirs",          2,   16,   8,    "Number of sampling directions around the hemisphere."),
            ("AO Steps",                "ao_steps",         2,   20,   10,   "Ray-march steps per direction — higher = smoother, slower."),
            ("AO Edge Depth Str.",      "ao_edge_depth_str",0.0, 5.0,  1.5,  "Strength of depth-Laplacian edge lines in AO Edge mode."),
            ("AO Edge Normal Str.",     "ao_edge_norm_str", 0.0, 5.0,  1.0,  "Strength of normal-gradient edge lines in AO Edge mode."),
            # ── Specular View group ───────────────────────────────────────────
            ("Specular Sensitivity",    "def_sens",         0.1, 5.0,  1.0,  "Sensitivity multiplier for the specular highlight extraction."),
            ("Specular Relief",         "def_relief",       0.0, 3.0,  1.0,  "Depth relief exaggeration for the specular surface view."),
            ("Specular Noise Floor",    "def_noise",        0.0, 1.0,  0.5,  "Minimum specular threshold — raise to suppress low-frequency noise."),
            # ── Image Quotient ────────────────────────────────────────────────
            ("IQ Specular Blend",       "def_spec",         0.0, 1.0,  0.0,  "Blend specular component back into IQ output (0=pure IQ, 1=full specular)."),
        ]
        for txt, key, start, end, default_val, tip in slider_configs:
            f = ctk.CTkFrame(self.slider_panel, fg_color="transparent")
            lbl = ctk.CTkLabel(f, text=txt); lbl.pack()
            s = ctk.CTkSlider(f, from_=start, to=end, command=self.on_slider_change)
            s.set(default_val); s.pack(pady=2, padx=10)
            self.sliders[key] = s; self.slider_widgets[key] = f; ToolTip(s, tip)
            # Double-click resets slider to its default value
            _dv = default_val  # capture per-iteration
            _k  = key
            def _make_reset(slider, dkey, dval):
                def _reset(event, _s=slider, _k=dkey, _v=dval):
                    _s.set(_v)
                    eng = self.render_engine.get()
                    if eng in self.engine_settings:
                        self.engine_settings[eng][_k] = _v
                    self.refresh_all()
                return _reset
            s.bind("<Double-Button-1>", _make_reset(s, _k, _dv))
            # ButtonRelease: clear drag flag → final full-resolution hillshade refresh
            _hs_keys = {'hs_alt','hs_azi','hs_z','hs_amb','nr_scale','nr_gain','nr_mode',
                        'rk_elevation','rk_n_dirs','rk_usm'}
            def _make_release(k):
                def _rel(evt, _key=k):
                    if _key in _hs_keys and getattr(self, '_slider_dragging', False):
                        self._slider_dragging = False
                        self.refresh_all()   # full-res pass after drag ends
                return _rel
            s.bind("<ButtonRelease-1>", _make_release(_k))
            ToolTip(s, tip + "\n\nDouble-click to reset to default.")
            f.pack(fill="x")

        # ── False-Colour Depth: colourmap selector (shown only for that engine) ──
        self._cmap_frame = ctk.CTkFrame(self.slider_panel, fg_color="transparent")
        ctk.CTkLabel(self._cmap_frame, text="Colourmap").pack()
        self._cmap_var = tk.StringVar(value="viridis")
        def _on_cmap(val):
            eng = self.render_engine.get()
            if eng in self.engine_settings: self.engine_settings[eng]['depth_cmap'] = val
            if not getattr(self, 'sweep_active', False): self.refresh_all()
        ctk.CTkOptionMenu(self._cmap_frame, values=["viridis","plasma","inferno","magma","cividis"],
                          variable=self._cmap_var, width=140,
                          command=_on_cmap).pack(pady=2, padx=10)
        ToolTip(self._cmap_frame, "Matplotlib colourmap for False-Colour Depth visualisation.")
        self.slider_widgets['_cmap'] = self._cmap_frame

        # ── Hillshade: depth-source selector (shown only for Hillshade engine) ──
        self._hs_src_frame = ctk.CTkFrame(self.slider_panel, fg_color="transparent")
        ctk.CTkLabel(self._hs_src_frame, text="Depth Source",
                     font=("Arial", 10), text_color="#94a3b8").pack()
        self._hs_src_var = tk.StringVar(value="poisson")
        def _on_hs_src(val):
            eng = self.render_engine.get()
            if eng in self.engine_settings: self.engine_settings[eng]['hs_depth_src'] = val
            if not getattr(self, 'sweep_active', False): self.refresh_all()
        ctk.CTkOptionMenu(self._hs_src_frame, values=["poisson","frankot"],
                          variable=self._hs_src_var, width=140,
                          command=_on_hs_src).pack(pady=2, padx=10)
        ToolTip(self._hs_src_frame,
                "Poisson = Fast Poisson (FFT) depth — lower noise.\n"
                "Frankot = Frankot-Chellappa depth — better flat objects.")
        self.slider_widgets['_hs_src'] = self._hs_src_frame

        bk_frame = ctk.CTkFrame(left)
        bk_frame.pack(side="bottom", fill="x", pady=4)
        ctk.CTkLabel(bk_frame, text="Safe States", font=("Arial", 12, "bold")).pack(pady=(4,0))
        self._add_btn(bk_frame, "Save Analysis State", self.save_bookmark, tip="Save all current settings as a preset.")
        self.bk_var = tk.StringVar(value="Load Safe State...")
        self.opt_bk = ctk.CTkOptionMenu(bk_frame, values=["Load Safe State..."], variable=self.bk_var, command=self.load_bookmark)
        self.opt_bk.pack(pady=(0,4), padx=10, fill="x"); self.requires_data_widgets.append(self.opt_bk); ToolTip(self.opt_bk, "Restore workspace state.")

        # ==========================================
        # CENTER PANE: VIEWPORT
        # ==========================================
        center_frame = ctk.CTkFrame(self, fg_color="transparent")
        center_frame.grid(row=0, column=1, sticky="nsew", padx=5, pady=10)
        # Row 0 = helper_bar, Row 1 = warning banner, Row 2 = progress bar (above viewport), Row 3 = main_view
        center_frame.grid_rowconfigure(3, weight=1); center_frame.grid_columnconfigure(0, weight=1)

        # ── Toolbar: use grid so both sides are always visible regardless of window width ──
        helper_bar = ctk.CTkFrame(center_frame, height=28, fg_color="transparent")
        helper_bar.grid(row=0, column=0, sticky="ew", pady=(0, 2))
        helper_bar.columnconfigure(0, weight=1, minsize=80)   # hint text expands, can shrink
        helper_bar.columnconfigure(1, weight=0, minsize=225)  # right buttons always visible

        # Left side: hint text (truncates gracefully when narrow)
        _hint_lbl = ctk.CTkLabel(helper_bar,
            text="Space+Drag: Pan  |  Scroll: Zoom  |  Shift+Drag: Crop  |  Dbl-Click: Reset Zoom",
            text_color="gray", font=("Arial", 11), anchor="w")
        _hint_lbl.grid(row=0, column=0, sticky="ew", padx=(10, 4))

        # Right side: fixed-width button strip — always visible
        # Badge lives here first so it is always in the fixed-width zone
        _right_bar = ctk.CTkFrame(helper_bar, fg_color="transparent")
        _right_bar.grid(row=0, column=1, sticky="e", padx=(0, 4))

        # ── V50 Transform Status Badge — in right bar, always visible ──────────
        self._v50_transform_badge = ctk.CTkLabel(
            _right_bar, text="", width=0, height=22,
            font=("Arial", 9, "bold"), text_color="#ff9944",
            fg_color="#3a1a00", corner_radius=4)
        # Not packed yet — shown/hidden by _v50_update_warning_banner()
        ToolTip(self._v50_transform_badge,
            "Display Transform is ACTIVE.\n"
            "One or more of: Horizontal Flip, Vertical Flip, Rotate 180°, Depth Invert.\n"
            "Go to 2D Renders → 🪞 Mirror / Invert Render to change or reset.")

        # Rotate buttons (leftmost in right bar)
        _btn_rot_l = ctk.CTkButton(_right_bar, text="↺", width=28, height=24,
            font=("Arial", 13), fg_color="#2a3a2a", hover_color="#3a5a3a",
            command=lambda: self._rotate_canvas(-90))
        _btn_rot_l.pack(side="left", padx=1)
        ToolTip(_btn_rot_l, "Rotate canvas 90° counter-clockwise.")
        _btn_rot_r = ctk.CTkButton(_right_bar, text="↻", width=28, height=24,
            font=("Arial", 13), fg_color="#2a3a2a", hover_color="#3a5a3a",
            command=lambda: self._rotate_canvas(90))
        _btn_rot_r.pack(side="left", padx=1)
        ToolTip(_btn_rot_r, "Rotate canvas 90° clockwise.")

        ctk.CTkLabel(_right_bar, text="|", font=("Arial", 12),
                     text_color="#444", width=8).pack(side="left", padx=(4, 4))

        ctk.CTkButton(_right_bar, text="−", width=28, height=24, fg_color="#2c3e50",
                      command=self._zoom_out_btn).pack(side="left", padx=1)
        ctk.CTkButton(_right_bar, text="+", width=28, height=24, fg_color="#2c3e50",
                      command=self._zoom_in_btn).pack(side="left", padx=1)
        ctk.CTkButton(_right_bar, text="⤢ Fit", width=60, height=24, fg_color="#2c3e50",
                      command=self._fit_to_screen).pack(side="left", padx=(1, 0))

        # ── Drag proxy resolution slider (Main View) ──────────────────────────
        # Controls main-view sharpness while dragging the light dome.
        # Takes effect on the next drag — no restart needed.
        # On release the full 2500 px proxy always renders clean regardless.
        ctk.CTkLabel(_right_bar, text="│", font=("Courier", 10),
                     text_color="#444", width=8).pack(side="left", padx=(6, 2))
        self._drag_proxy_px_var = tk.IntVar(value=1250)
        _dp_lbl = ctk.CTkLabel(_right_bar,
                               text="Main View drag: 1250 px",
                               font=("Arial", 9, "bold"), text_color="#7ec8e3",
                               width=132, anchor="w")
        _dp_lbl.pack(side="left", padx=(0, 2))
        def _dp_update(v):
            val = int(float(v))
            self._drag_proxy_px_var.set(val)
            _dp_lbl.configure(text=f"Main View drag: {val} px")
        ctk.CTkSlider(_right_bar, from_=400, to=1500,
                      variable=self._drag_proxy_px_var,
                      number_of_steps=11,   # 400, 500, …, 1400, 1500
                      width=90, height=16,
                      command=_dp_update).pack(side="left", padx=(0, 4))
        ToolTip(_dp_lbl,
                "Main View drag resolution — how sharp the main viewport looks\n"
                "while you drag the light dome.\n\n"
                "Lower (400–600 px): fastest, slightly soft during drag.\n"
                "Default (1100 px): good balance — recommended.\n"
                "Higher (1300–1500 px): near-full quality during drag,\n"
                "  may feel slower on 20+ image captures.\n\n"
                "Takes effect on your NEXT drag (touch the dome once).\n"
                "On release, the full 2500 px proxy always renders clean.")

        # ── V50 Transform Warning Banner (row 1, hidden until transform active) ──
        self._v50_warn_bar = ctk.CTkFrame(center_frame, height=28,
                                          fg_color="#4a2800", corner_radius=0)
        # Not gridded yet — shown/hidden dynamically by _v50_update_warning_banner()
        _warn_icon = ctk.CTkLabel(self._v50_warn_bar, text="⚠",
                                  font=("Arial", 13), text_color="#ffaa33", width=22)
        _warn_icon.pack(side="left", padx=(6, 2))
        self._v50_warn_text = ctk.CTkLabel(
            self._v50_warn_bar, text="",
            font=("Arial", 10, "bold"), text_color="#ffcc66", anchor="w")
        self._v50_warn_text.pack(side="left", fill="x", expand=True, padx=2)
        ctk.CTkButton(
            self._v50_warn_bar, text="✕ Reset Transforms", height=20, width=130,
            font=("Arial", 9, "bold"), fg_color="#6a3800", hover_color="#993300",
            text_color="#ffdd99",
            command=self._v50_reset_all_transforms
        ).pack(side="right", padx=6, pady=4)
        ToolTip(self._v50_warn_bar,
            "One or more V50 display transforms are active.\n"
            "The viewport and all depth exports use this orientation.\n\n"
            "Click '✕ Reset Transforms' to restore original orientation.\n"
            "Or go to 2D Renders → 🪞 Mirror / Invert Render to adjust.")

        # ── Processing progress bar (row 2, above viewport) ──────────────────
        # Visible and prominent during processing; hidden when idle.
        self._proc_bar_frame = ctk.CTkFrame(center_frame, height=28,
                                             fg_color="#0d1f12", corner_radius=0)
        self._proc_bar_frame.grid(row=2, column=0, sticky="ew")
        self._proc_bar_frame.grid_propagate(False)

        # Pure tk.Canvas — all items (fill rectangle, icon, text) are drawn here.
        # Avoids z-ordering fights with CTk's continuous background redraws.
        self._proc_canvas = tk.Canvas(self._proc_bar_frame, bg="#0d1f12",
                                      highlightthickness=0, height=28)
        self._proc_canvas.pack(fill="both", expand=True)

        # Reserve canvas item IDs
        self._proc_canvas_fill = self._proc_canvas.create_rectangle(
            0, 0, 0, 28, fill="#1a4a22", outline="", tags="fill")
        self._proc_canvas_icon = self._proc_canvas.create_text(
            16, 14, text="⚙", fill="#4ade80", font=("Arial", 13), anchor="center")
        self._proc_canvas_text = self._proc_canvas.create_text(
            36, 14, text="Ready", fill="#4ade80",
            font=("Arial", 11, "bold"), anchor="w")

        self._proc_progress = 0.0

        def _redraw_proc_bar(event=None):
            cw = max(1, self._proc_canvas.winfo_width())
            ch = max(1, self._proc_canvas.winfo_height())
            # Fill bar: starts just after the text, fills right
            # Get text right edge so fill sits to the right of the label
            try:
                tx1, _, tx2, _ = self._proc_canvas.bbox(self._proc_canvas_text)
                fill_start = tx2 + 8
            except Exception:
                fill_start = 200
            fill_end = fill_start + int((cw - fill_start) * self._proc_progress)
            self._proc_canvas.coords(self._proc_canvas_fill,
                                     fill_start, 3, max(fill_start, fill_end), ch - 3)
            self._proc_canvas.tag_raise(self._proc_canvas_icon)
            self._proc_canvas.tag_raise(self._proc_canvas_text)

        self._proc_canvas.bind("<Configure>", _redraw_proc_bar)
        self._redraw_proc_bar = _redraw_proc_bar

        # Proxy label attrs so existing _show_status calls work
        class _FakeLabel:
            def __init__(self_, canvas, item_id):
                self_._c = canvas; self_._id = item_id
            def configure(self_, text=None, text_color=None, **kw):
                if text is not None:
                    self_._c.itemconfigure(self_._id, text=text)
                if text_color is not None:
                    self_._c.itemconfigure(self_._id, fill=text_color)
                self_._c.after_idle(self_._c.master.master._redraw_proc_bar
                                    if hasattr(self_._c.master.master, '_redraw_proc_bar')
                                    else lambda: None)

        self._proc_bar_lbl = _FakeLabel(self._proc_canvas, self._proc_canvas_text)

        def _set_proc_progress(frac):
            self._proc_progress = max(0.0, min(1.0, float(frac)))
            self._redraw_proc_bar()
        self._set_proc_progress = _set_proc_progress

        class _CompatBar:
            def __init__(self_, setter): self_._s = setter
            def set(self_, v): self_._s(float(v))
        self.progress = _CompatBar(_set_proc_progress)

        self._proc_bar_frame.grid_remove()

        self.main_view = tk.Canvas(center_frame, bg="#101010", highlightthickness=0)
        self.main_view.grid(row=3, column=0, sticky="nsew")
