        # ── Space+drag pan ────────────────────────────────────────────────────
        # Problem: CTkScrollableFrame binds Space at widget level and returns "break",
        # which stops ALL further binding tags including bind_all. So bind_all never fires.
        # Solution: Force keyboard focus to the canvas whenever the mouse enters it,
        # using focus_force() (more aggressive than focus_set() — works on macOS CTk).
        # With the canvas owning keyboard focus, our canvas-level binding fires FIRST,
        # before CTkScrollableFrame ever sees the key event.
        def _space_press(e):
            setattr(self, 'space_pressed', True)
            self.main_view.config(cursor="fleur")
            return "break"   # stop Space from propagating to CTkScrollableFrame
        def _space_release(e):
            setattr(self, 'space_pressed', False)
            self.main_view.config(cursor="")
            return "break"
        # ONLY bind on canvas itself — no bind_all which fires too late
        self.main_view.bind("<KeyPress-space>",    _space_press)
        self.main_view.bind("<KeyRelease-space>",  _space_release)
        # force_focus on Enter: mouse enters canvas → canvas steals keyboard focus
        # This ensures Space events land on the canvas, not the scrollable frame
        self.main_view.bind("<Enter>", lambda e: self.main_view.focus_force())
        # Also steal focus on click (belt-and-suspenders)
        self.main_view.bind("<ButtonPress-1>", lambda e: self.main_view.focus_force(), add="+")
        # ── Middle-mouse-button pan (always works, no focus dependency) ──────
        self.main_view.bind("<ButtonPress-2>",   lambda e: self._mmb_pan_start(e))
        self.main_view.bind("<B2-Motion>",        lambda e: self._mmb_pan_drag(e))
        self.main_view.bind("<ButtonRelease-2>",  lambda e: self._mmb_pan_end(e))

        # ── Global keyboard shortcuts ────────────────────────────────────────
        # Cmd on macOS, Ctrl on Windows/Linux — bind both
        for _mod in ('<Control-', '<Command-'):
            self.bind(f'{_mod}r>', lambda e: self.run_processing())
            self.bind(f'{_mod}R>', lambda e: self.run_processing())
            self.bind(f'{_mod}e>', lambda e: self.export_highres_tiff())
            self.bind(f'{_mod}E>', lambda e: self.export_highres_tiff())
            self.bind(f'{_mod}3>', lambda e: self.popout_viewer())
            self.bind(f'{_mod}0>', lambda e: self._reset_view())
            self.bind(f'{_mod}s>', lambda e: self.save_session())
            self.bind(f'{_mod}S>', lambda e: self.save_session())
        # C = toggle clay, left/right = cycle render engine, F = fit to screen
        self.bind('<c>', lambda e: self._kbd_toggle_clay())
        self.bind('<C>', lambda e: self._kbd_toggle_clay())
        self.bind('<Left>',  lambda e: self._kbd_cycle_engine(-1))
        self.bind('<Right>', lambda e: self._kbd_cycle_engine(+1))
        self.bind('<f>', lambda e: self._fit_to_screen())
        self.bind('<F>', lambda e: self._fit_to_screen())
