            _val_lbl.pack(side="right")
            def _upd(v, _lbl=_val_lbl): _lbl.configure(text=f"{float(v):.1f}")
            _sl = ctk.CTkSlider(f, from_=start, to=end, variable=_var,
                                 number_of_steps=int((end-start)/res),
                                 command=_upd)
            _sl.pack(side="left", fill="x", expand=True, padx=(0, 4))
            ToolTip(_sl, _sharp_tips.get(key, lbl))
