        if not hasattr(self, '_3d_sliders'): self._3d_sliders = {}
        def make_ui_slider(parent, label, key, start, end, default, tip, is_int=False):
            lbl = ctk.CTkLabel(parent, text=label, font=("Arial", 11)); lbl.pack(anchor="w", pady=(2,0), padx=10)
            def default_cmd(v): self.update_shared(key, v, is_int)
            sl = ctk.CTkSlider(parent, from_=start, to=end, command=default_cmd); sl.set(default); sl.pack(pady=2, fill="x", padx=10); ToolTip(sl, tip)
