        geo_f = ctk.CTkFrame(_exports_body); geo_f.pack(fill="x", pady=2, padx=10)

        make_ui_slider(geo_f, "Mesh Density Decimation", 'step', 1, 10, 2, "Controls vertex density of the 3D mesh.\nStep 1 = full resolution (very large file).\nStep 2-4 = good balance of detail and file size.\nStep 5-10 = fast preview, coarse geometry.", True)
        make_ui_slider(geo_f, "Z-Axis Height Exaggeration", 'height', 10, 5000, 300, "Scales the vertical (Z) depth of the mesh.\nLow values = flat, subtle relief.\nHigh values = exaggerated topography for visual clarity.\nFor physical accuracy match to your real object depth.\nRange: 10–5000 (default 300).")
        make_ui_slider(geo_f, "Detail vs Shape", 'shape_blend', 0.0, 1.0, 0.55, "Controls how much macro-scale shape is preserved in the 3D mesh.\n0.0 = FULL original surface shape (buckle, warp, curvature fully visible).\n0.3 = balanced default — good macro form + detail (recommended).\n0.7 = detail-dominant — flatter base, emphasises fine surface marks.\n1.0 = detail only — all low-frequency shape stripped (flat base).\n\nFor manuscripts/parchment: use 0.0–0.3 to see the natural buckle.\nFor coins/flat engravings: use 0.5–0.8 for clean flat relief.\nFor books/sculpture: 0.2–0.4 shows natural curvature.")
        make_ui_slider(geo_f, "Warp Flatten (Taco Fix)", 'hp_sigma', 0.0, 1.0, 0.0, "High-pass filter applied to depth before meshing.\nRemoves large-scale bowl warping caused by Poisson integration drift.\nAlso called 'Taco Fix' — eliminates the potato-chip curl in flat objects.\nIncrease if your model looks dished or curled at the edges.")
        make_ui_slider(geo_f, "Broad Warp Remove", 'warp_rem', 0.0, 1.0, 0.0, "Removes broad curvature / warp from the depth surface.\n0 = minimal (removes only very low frequency drift).\n0.5 = moderate (removes gentle bow or tilt).\n1.0 = aggressive (removes all frequencies below ~50% of image width).\n\nUse when the mesh has an overall bowl, dome or tilt.\nCombine with Shape Preservation for best results.")
        make_ui_slider(geo_f, "Fine Detail Boost", 'micro_relief', 0.0, 3.0, 0.0, "Boosts fine high-frequency surface texture in the 3D viewer.\n0 = natural depth. 1-2 = good for shallow coin or engraving detail.\n3 = maximum — may introduce noise on flat surfaces.")
        make_ui_slider(geo_f, "Mesh Smoothing", 'mesh_smooth', 0.0, 5.0, 0.0, "Applies Gaussian smoothing to the depth grid before meshing.\nReduces scan noise and polygon noise at the cost of fine detail.\nUse sparingly — 0.5-1.5 is usually sufficient.")
        make_ui_slider(geo_f,"Depth Outlier Clip  %","depth_clip_pct",0.01,4.9,0.5,
            "Clips top/bottom N% of depth values before meshing.\n\n"
            "Stops tears, holes and ink spikes compressing fine relief.\n"
            "0.5% default. 1.5-3% for damaged manuscripts. 0.2% for coins.")
        make_ui_slider(geo_f,"X-Tilt Correction deg","x_tilt",-15.,15.,0.,
            "Subtracts a left-right linear tilt plane from the depth surface.\n\n"
            "Corrects copystand slope across X axis. Range +-1 to +-5 deg.\n"
            "Use alongside Y-Tilt to fully level the capture.")
        make_ui_slider(geo_f,"Y-Tilt Correction deg","y_tilt",-15.,15.,0.,
            "Subtracts a front-back linear tilt plane from the depth surface.\n\n"
            "Corrects copystand slope across Y axis. Range +-1 to +-5 deg.\n"
            "Use alongside X-Tilt to fully level the capture.")
        
        # --- NEW CUSTOM CLAY COLOR UI ---
        color_frame = ctk.CTkFrame(geo_f, fg_color="transparent")
        color_frame.pack(fill="x", pady=4)
        
        def _update_clay_color(*args):
            self.shared_state['use_custom_clay'].value = 1 if self.use_custom_clay.get() else 0
            r, g, b_val = {"Red": (0.8, 0.2, 0.2), "Blue": (0.2, 0.4, 0.8), "Green": (0.2, 0.7, 0.3), "Mustard": (0.8, 0.7, 0.2), "Grey": (0.6, 0.6, 0.6)}.get(self.clay_color_name.get(), (0.6, 0.6, 0.6))
            self.shared_state['clay_r'].value = r
            self.shared_state['clay_g'].value = g
            self.shared_state['clay_b'].value = b_val

        _chk_clay = ctk.CTkCheckBox(color_frame, text="Custom Clay", variable=self.use_custom_clay, command=_update_clay_color); _chk_clay.pack(side="left")
        ToolTip(_chk_clay, "Replace photographic colour with a uniform clay material.\nUseful for archival renders that emphasise form over surface colour.")
        _opt_clay = ctk.CTkOptionMenu(color_frame, values=["Grey", "Red", "Blue", "Green", "Mustard"], variable=self.clay_color_name, command=_update_clay_color, width=90); _opt_clay.pack(side="right")
        ToolTip(_opt_clay, "Choose the clay colour applied when Custom Clay is enabled.")
        _update_clay_color() # init default
        
        make_ui_slider(geo_f, "Clay Blend (Colour→Clay)", 'clay_blend', 0.0, 1.0, 0.0, "Cross-fades from the photographic vertex colour to the selected clay colour.\n0 = full photo colour. 1 = full clay. 0.5 = equal blend.", False)

        flip_f = ctk.CTkFrame(geo_f, fg_color="transparent"); flip_f.pack(fill="x", pady=2)
        ctk.CTkLabel(flip_f, text="Geometry Flip:", font=("Arial", 11)).pack(side="left", padx=5)
        for axis, key, tip in [("X", 'fx', "Flip the mesh left-right."), ("Y", 'fy', "Flip the mesh top-bottom. Enable if the model appears upside-down."), ("Z", 'fz', "Invert depth — raises valleys and lowers peaks.\n\nIn the 3D viewer this works even if normals are inverted because\nthe viewer uses abs(N·L) for lighting. If the 2D engines show a\nblack image, this was the sign-flip issue — re-process to fix it\n(HELIO now auto-orients normals to Nz>0 after processing).")]:
            _chk_flip = ctk.CTkCheckBox(flip_f, text=axis, width=40, command=lambda k=key: self.update_shared(k, -1 if self.shared_state[k].value == 1 else 1, True)); _chk_flip.pack(side="left", padx=5)
            ToolTip(_chk_flip, tip)

        # --- 3D MATERIAL PROPERTIES ---
        # lbl_ba_state kept as hidden ref so toggle_3d_before_after doesn't crash
        self.lbl_ba_state = ctk.CTkLabel(geo_f, text="", font=("Arial", 10), text_color="#27ae60")
        ctk.CTkLabel(geo_f, text="3D Material Properties", font=("Arial", 12, "bold"), text_color="#3498db").pack(pady=(8, 2))
        make_ui_slider(geo_f, "Ambient Strength", 'ambient_str', 0.0, 1.0, 0.15, "Base light level added to every surface regardless of angle.\nLow (0.05-0.2) = dramatic shadows. High (0.5+) = uniformly bright, reduces shadow contrast.")
        make_ui_slider(geo_f, "Diffuse (Matte) Strength", 'diffuse_str', 0.0, 2.0, 1.0, "Controls how strongly the surface responds to the light direction.\n1.0 = physically correct matte. Lower = flatter look. Higher = exaggerated shading.")
        make_ui_slider(geo_f, "Specular (Shine) Strength", 'specular_str', 0.0, 2.0, 0.4, "Intensity of the specular (glossy) highlight.\n0 = fully matte. 0.4 = subtle sheen (good default). 2.0 = very shiny.")
        make_ui_slider(geo_f, "Shininess", 'shininess', 1.0, 128.0, 32.0, "Controls the size and sharpness of the specular highlight.\n1 = broad soft glow. 32 = medium (plastic-like). 128 = tight sharp spot (polished metal).")

        ctk.CTkLabel(geo_f, text="Display Tone Controls", font=("Arial", 12, "bold"), text_color="#2ecc71").pack(pady=(10, 2))
        make_ui_slider(geo_f, "Display Gamma", 'viewer_gamma', 0.3, 3.0, 1.0,
            "Apply gamma correction to the 3D viewer display.\n"
            "1.0 = linear (default). <1.0 = brighter midtones. >1.0 = darker midtones.\n"
            "Does not affect exports — display only.")
        make_ui_slider(geo_f, "Colour Saturation", 'viewer_saturation', 0.0, 2.0, 1.0,
            "Adjust colour saturation in the 3D viewer.\n"
            "0.0 = greyscale. 1.0 = natural (default). 2.0 = vivid.\n"
            "Useful for emphasising subtle colour differences on manuscripts.")
        make_ui_slider(geo_f, "Shadow Lift", 'shadow_lift', 0.0, 0.4, 0.0,
            "Lifts the shadow floor — prevents very dark areas going pure black.\n"
            "0.0 = natural deep shadows. 0.2 = lifted shadows (film look).\n"
            "Useful for raking light views where shadows obscure detail.")
        make_ui_slider(geo_f, "Highlight Clip", 'highlight_clip', 0.5, 1.0, 1.0,
            "Clamps the highlight ceiling — prevents specular hot spots burning out.\n"
            "1.0 = natural full range. 0.7 = soft roll-off on bright highlights.\n"
            "Useful for glossy or metallic surfaces.")

        # ── Global Image Adjustments ───────────────────────────────────────────
        ctk.CTkLabel(geo_f, text="Global Image Adjustments",
                     font=("Arial", 12, "bold"), text_color="#a78bfa").pack(pady=(14, 2))
        ctk.CTkLabel(geo_f,
            text="Applied to the main 2D viewport. Use alongside Analysis Adjustments\n"
                 "for refined per-engine tuning.",
            font=("Arial", 9), text_color="#64748b",
            wraplength=280, justify="left").pack(padx=10, anchor="w")
        make_ui_slider(geo_f, "Whites", 'global_whites', 0.0, 2.0, 1.0,
            "Expand or compress the upper tonal range.\n"
            "1.0 = no change. >1.0 = pull highlights brighter (useful for\n"
            "low-contrast surfaces like worn stone or stained parchment).\n"
            "<1.0 = roll-off highlights (protect overexposed areas).")
        make_ui_slider(geo_f, "Blacks", 'global_blacks', 0.0, 1.0, 0.0,
            "Lift the black point — the lowest tonal floor.\n"
            "0.0 = pure black in darkest areas. 0.1–0.3 = 'lifted' blacks\n"
            "showing detail in deep shadow regions (e.g. raking-light valleys).")
        make_ui_slider(geo_f, "Midtone Push", 'global_midtone', 0.5, 2.0, 1.0,
            "Gamma-style curve on the midtones only.\n"
            "1.0 = linear. <1.0 = darken midtones (more punch).\n"
            ">1.0 = lift midtones (reveal detail in mid-grey regions).\n"
            "Non-destructive — does not clip highlights or blacks.")
        make_ui_slider(geo_f, "Local Contrast (Clarity)", 'global_clarity', 0.0, 3.0, 0.0,
            "Boosts mid-frequency local contrast — similar to Lightroom 'Clarity'.\n"
            "0.0 = no effect. 1.0 = moderate (good for text legibility).\n"
            "2–3 = strong (use for toolmark and inscription enhancement).\n"
            "Applied as unsharp mask at a large radius (8% of image height).")
        make_ui_slider(geo_f, "Texture (Fine Detail)", 'global_texture', 0.0, 2.0, 0.0,
            "Boosts fine-frequency local contrast — similar to Lightroom 'Texture'.\n"
            "0.0 = no effect. 1.0 = moderate fine detail enhancement.\n"
            "Use to bring out fibre structure, toolmarks, parchment grain.\n"
            "Applied as unsharp mask at a small radius (1.5% of image height).")
        make_ui_slider(geo_f, "Haze Removal", 'global_dehaze', 0.0, 1.0, 0.0,
            "Stretches the tonal range of the current render to fill [0,1].\n"
            "Equivalent to 'Auto Levels' — removes any overall grey haze.\n"
            "0.0 = no adjustment. 1.0 = full auto-stretch.\n"
            "Useful when engines produce low-contrast outputs on flat objects.")

        # ── 3D-4: High-quality normals toggle ─────────────────────────────
        ctk.CTkLabel(geo_f, text="Render Quality", font=("Arial", 11, "bold"),
                     text_color="#a78bfa").pack(pady=(10,2), anchor="w", padx=8)
        _hq_row = ctk.CTkFrame(geo_f, fg_color="transparent"); _hq_row.pack(fill="x", padx=8)
        self._hq_normals_var = tk.BooleanVar(value=False)
        def _toggle_hq():
            self.shared_state['hq_normals'].value = int(self._hq_normals_var.get())
        ctk.CTkCheckBox(_hq_row, text="High-Quality Normals (uses normals_full)",
                        variable=self._hq_normals_var,
                        command=_toggle_hq, font=("Arial", 11),
                        text_color="#a78bfa").pack(side="left")
        ToolTip(_hq_row,
                "When OFF (default): vertex normals derived from the depth proxy\n"
                "(fast, slightly blocky on fine features).\n\n"
                "When ON: vertex normals derived directly from normals_full —\n"
                "the full per-pixel PS normal map.  Much finer surface detail\n"
                "visible on manuscript marks, but slightly slower mesh rebuild.\n\n"
                "Recommended: enable after processing is complete and you want\n"
                "to inspect fine drypoint marks in the 3D viewer.")

        ctk.CTkLabel(geo_f, text="3D Export Pipeline", font=("Arial", 12, "bold"), text_color="#f39c12").pack(pady=(10,2))
        make_ui_slider(geo_f, "Export Step (Decimation)", 'export_step', 1, 10, 2, "Vertex grid step for exported files (OBJ, GLB, PLY).\nStep 1 = full resolution — very large file, best quality.\nStep 2 = half resolution — good balance for most uses.\nStep 4-10 = fast preview exports.", True)
        self.lbl_export_est = ctk.CTkLabel(geo_f, text="Est. Size: N/A", text_color="gray", font=("Arial", 11))
        self.lbl_export_est.pack(pady=2)

        # --- Export high-frequency detail controls ---
        exp_hf_frame = ctk.CTkFrame(geo_f, fg_color="transparent"); exp_hf_frame.pack(fill="x", padx=8, pady=(4,0))
        ctk.CTkLabel(exp_hf_frame, text="Export Detail Cutoff (High-Freq Only)", font=("Arial", 11), text_color="#f39c12").pack(anchor="w")
        self.export_hf_var = tk.DoubleVar(value=0.05)
        exp_hf_slider = ctk.CTkSlider(exp_hf_frame, from_=0.01, to=0.5, variable=self.export_hf_var)
        exp_hf_slider.pack(fill="x", pady=2)
        ToolTip(exp_hf_slider, "Spatial frequency cutoff for the exported mesh.\nLow (0.01-0.05) = flat base, finest detail only.\nHigh (0.3-0.5) = more macro shape included.\nSingle clean pass from raw Poisson depth.\nFor copper engravings try 0.03-0.08.")
        ctk.CTkLabel(exp_hf_frame, text="<- Detail only              More shape ->", font=("Arial", 10), text_color="gray").pack(anchor="w")
        ctk.CTkLabel(exp_hf_frame, text="Export Detail Amplification", font=("Arial", 11), text_color="#f39c12").pack(anchor="w", pady=(6,0))
        self.export_amp_var = tk.DoubleVar(value=1.0)
        exp_amp_slider = ctk.CTkSlider(exp_hf_frame, from_=0.5, to=8.0, variable=self.export_amp_var)
        exp_amp_slider.pack(fill="x", pady=2)
        ToolTip(exp_amp_slider, "Multiplies the high-frequency depth signal.\n1.0 = natural, 2-4 = good for shallow engravings.\nOnly amplifies detail — never the base warp.")
        ctk.CTkLabel(exp_hf_frame, text="<- Subtle                   Strong ->", font=("Arial", 10), text_color="gray").pack(anchor="w")
        ctk.CTkLabel(exp_hf_frame, text="Export Vertex Brightness", font=("Arial", 11), text_color="#f39c12").pack(anchor="w", pady=(6,0))
        self.export_brightness_var = tk.DoubleVar(value=1.0)
        exp_bright_slider = ctk.CTkSlider(exp_hf_frame, from_=0.5, to=2.5, variable=self.export_brightness_var)
        exp_bright_slider.pack(fill="x", pady=2)
        ToolTip(exp_bright_slider, "Gamma brightness applied to vertex colours on export.\n1.0 = original (no change).\n1.2–1.5 = good for Sketchfab which tends to render dark.\n2.0+ = very bright — use for preview only.\n\nIf your model looks dark in Sketchfab, try 1.3–1.5.")
        ctk.CTkLabel(exp_hf_frame, text="<- Darker   1.0=Natural   Brighter ->", font=("Arial", 10), text_color="gray").pack(anchor="w")
        
        ef = ctk.CTkFrame(geo_f, fg_color="transparent"); ef.pack(fill="x", pady=2)

        # ── Mesh options ────────────────────────────────────────────────────
        _mesh_card = ctk.CTkFrame(ef, fg_color="#131c28", corner_radius=6)
        _mesh_card.pack(fill="x", padx=8, pady=(0, 4))
        _chk_wt = ctk.CTkCheckBox(_mesh_card, text="Watertight Base",
            variable=self.watertight_var, font=("Arial", 11))
        _chk_wt.pack(anchor="w", padx=10, pady=(6, 2))
        ToolTip(_chk_wt, "Adds a flat bottom and sealed side walls to the mesh.\nRequired for 3D printing and any application needing a closed solid.")
        _chk_bs = ctk.CTkCheckBox(_mesh_card, text="Black Sides & Bottom",
            variable=self.black_sides_var, font=("Arial", 11), text_color="#aaaaaa")
        _chk_bs.pack(anchor="w", padx=28, pady=(0, 2))
        ToolTip(_chk_bs, "When Watertight Base is on: makes the sides and bottom faces\n"
                "solid black instead of sampling from the surface texture.\n"
                "Prevents colour bleed / texture stretch on non-surface geometry.\n"
                "Recommended for Sketchfab, web viewers, and 3D printing.")
        _chk_vc = ctk.CTkCheckBox(_mesh_card, text="Include Vertex Colours",
            variable=self.vtx_color_var, font=("Arial", 11))
        _chk_vc.pack(anchor="w", padx=10, pady=(0, 6))
        ToolTip(_chk_vc, "Embeds the photographic colour as per-vertex colour in the exported mesh.\nDisable for plain grey mesh (useful for post-processing in Blender or ZBrush).")

        # ── Sketchfab PBR Package ───────────────────────────────────────────
        _pbr_card = ctk.CTkFrame(ef, fg_color="#0e1c10", corner_radius=6)
        _pbr_card.pack(fill="x", padx=8, pady=(0, 4))

        # Header row — main toggle
        _pbr_hdr = ctk.CTkFrame(_pbr_card, fg_color="transparent")
        _pbr_hdr.pack(fill="x", padx=10, pady=(6, 2))
        _chk_sf = ctk.CTkCheckBox(_pbr_hdr, text="Sketchfab PBR Package (ZIP)",
            variable=self.sketchfab_var, text_color="#4ade80", font=("Arial", 11, "bold"))
        _chk_sf.pack(side="left")
        ToolTip(_chk_sf,
            "Exports a full PBR texture package alongside the mesh:\n"
            "  • Base colour PNG\n  • Normal map PNG (gamma-encoded for Sketchfab)\n"
            "  • Roughness map\n  • Specular map\n  • Ambient Occlusion map\n"
            "  • HP-filtered Displacement 16-bit PNG\n"
            "  • Georeferenced 32-bit float depth TIF + README\n"
            "  • .mtl material file\n"
            "Upload the entire folder to Sketchfab for a fully textured model.")

        # Sub-options indented block
        _pbr_sub = ctk.CTkFrame(_pbr_card, fg_color="#111f13", corner_radius=4)
        _pbr_sub.pack(fill="x", padx=10, pady=(0, 8))

        # Output format row
        _fmt_row = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _fmt_row.pack(fill="x", padx=8, pady=(6, 2))
        _chk_zip = ctk.CTkCheckBox(_fmt_row, text="ZIP output",
            variable=self.zip_export_var, font=("Arial", 10), text_color="#94a3b8")
        _chk_zip.pack(side="left", padx=(0, 16))
        ToolTip(_chk_zip,
            "Ticked (default): writes a Sketchfab-ready .zip alongside the OBJ/MTL/PNGs.\n"
            "Untick to export raw files without zipping — significantly faster.")
        _chk_sf_jpg = ctk.CTkCheckBox(_fmt_row, text="JPEG textures",
            variable=self.sketchfab_jpeg_var, font=("Arial", 10), text_color="#f59e42")
        _chk_sf_jpg.pack(side="left")
        ToolTip(_chk_sf_jpg,
            "JPEG Q90 for baseColor / roughness / specular — ~85% smaller than PNG.\n"
            "Normal map always stays PNG (JPEG artefacts corrupt surface direction data).\n"
            "AO + Displacement excluded in JPEG mode — smallest possible Sketchfab ZIP.\n"
            "Leave unticked for lossless archival PNG quality.")

        # Maps row
        _maps_row = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _maps_row.pack(fill="x", padx=8, pady=(2, 2))
        ctk.CTkLabel(_maps_row, text="Include:", font=("Arial", 10),
            text_color="#64748b", width=52).pack(side="left")
        _chk_ao = ctk.CTkCheckBox(_maps_row, text="AO",
            variable=self.pbr_ao_var, font=("Arial", 10), text_color="#94a3b8")
        _chk_ao.pack(side="left", padx=(0, 12))
        ToolTip(_chk_ao, "Compute and include an Ambient Occlusion map.\nHorizon-based AO from the normal map — darker in crevices, brighter on raised areas.")
        _chk_disp = ctk.CTkCheckBox(_maps_row, text="Displacement",
            variable=self.pbr_disp_var, font=("Arial", 10), text_color="#94a3b8")
        _chk_disp.pack(side="left", padx=(0, 12))
        ToolTip(_chk_disp, "Include HP-filtered 16-bit displacement map.\nSame pipeline as the 3D mesh export — integration bowl removed.")
        _chk_render = ctk.CTkCheckBox(_maps_row, text="Baked Render",
            variable=self.pbr_render_var, font=("Arial", 10), text_color="#a3c4e8")
        _chk_render.pack(side="left", padx=(0, 12))
        ToolTip(_chk_render,
            "Export a colour PNG of the current render engine view baked at full resolution.\n\n"
            "Captures whatever is active in the render engine dropdown — raking hillshade,\n"
            "Specular Enhancement, HBAO, Image Quotient, etc. — as a colour texture map.\n"
            "Useful as a detail/emissive texture in Sketchfab or as a reference image.\n\n"
            "File: {name}_render_{engine}.png\n"
            "Matches exactly what you see in the 3D viewer mesh colour.")
        # Heatmap row — own row so it's always visible
        self.export_heatmap_var = tk.BooleanVar(value=False)
        _heat_row2 = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _heat_row2.pack(fill="x", padx=8, pady=(2, 2))
        ctk.CTkLabel(_heat_row2, text="Include:", font=("Arial", 10),
            text_color="#64748b", width=52).pack(side="left")
        _chk_heat = ctk.CTkCheckBox(_heat_row2, text="Elevation Heatmap (turbo colourmap)",
            variable=self.export_heatmap_var, font=("Arial", 10), text_color="#f59e42")
        _chk_heat.pack(side="left")
        ToolTip(_chk_heat,
            "Adds an elevation heatmap PNG to the Sketchfab PBR package.\n"
            "Depth values mapped to turbo colourmap (blue=low → red=high).\n"
            "Useful as a height reference or secondary emissive texture.\n"
            "File: {name}_elevation_heatmap.png")

        # Normal encoding — split across two rows so nothing is clipped
        _norm_row1 = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _norm_row1.pack(fill="x", padx=8, pady=(2, 0))
        ctk.CTkLabel(_norm_row1, text="Normals:", font=("Arial", 10),
            text_color="#64748b", width=52).pack(side="left")
        _chk_nl = ctk.CTkCheckBox(_norm_row1, text="Linear→sRGB",
            variable=self.normal_linear_var, font=("Arial", 10), text_color="#94a3b8")
        _chk_nl.pack(side="left", padx=(0, 12))
        ToolTip(_chk_nl,
            "Gamma-encode the normal map PNG (1/2.2 power curve).\n\n"
            "OFF (default): Normal map stays LINEAR — correct for Sketchfab, Blender,\n"
            "Unity, and any modern PBR renderer that loads normals as non-colour data.\n\n"
            "ON: Apply sRGB pre-encoding. Only enable if the target renderer forces\n"
            "normal map textures through sRGB decode and you cannot override that.")
        _chk_fy = ctk.CTkCheckBox(_norm_row1, text="Flip Y",
            variable=self.normal_flip_y_var, font=("Arial", 10), text_color="#94a3b8")
        _chk_fy.pack(side="left", padx=(0, 12))
        ToolTip(_chk_fy,
            "Invert the green channel of the normal map.\n\n"
            "HELIO PS normals are in image-space (Y increases downward).\n"
            "Sketchfab, Unity (OpenGL), and Three.js use Y-up tangent space.\n"
            "Leave ON for those targets. Turn OFF for Unreal Engine (DirectX Y-down).")

        # Second normals row — live-view overrides
        _norm_row2 = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _norm_row2.pack(fill="x", padx=8, pady=(2, 4))
        ctk.CTkLabel(_norm_row2, text="Live view:", font=("Arial", 10),
            text_color="#64748b", width=52).pack(side="left")
        def _on_invert_normals():
            self.shared_state['normal_invert'].value = 1 if self.normal_invert_var.get() else 0
            self.refresh_all()
        _chk_ni = ctk.CTkCheckBox(_norm_row2, text="Invert Normals",
            variable=self.normal_invert_var, font=("Arial", 10), text_color="#e07070",
            command=_on_invert_normals)
        _chk_ni.pack(side="left", padx=(0, 0))
        ToolTip(_chk_ni,
            "Invert Normals — flips Nx and Ny in the live view AND in all exports.\n\n"
            "HELIO auto-orients normals after processing (Nz forced positive)\n"
            "so this should rarely be needed.\n\n"
            "Use this if:\n"
            "  • The surface appears inverted — hills look like valleys\n"
            "  • 3D viewer shows relief as cavities instead of protrusions\n"
            "  • Exported mesh is black in Revo Studio / Blender\n\n"
            "When ticked, exports (OBJ/STL/GLB) automatically apply the same\n"
            "flip so the exported mesh geometry matches the live view.\n\n"
            "Display + export — does not modify the stored normals_full.")

        # Texture resolution row
        _res_row = ctk.CTkFrame(_pbr_sub, fg_color="transparent")
        _res_row.pack(fill="x", padx=8, pady=(2, 6))
        ctk.CTkLabel(_res_row, text="Tex Res:", font=("Arial", 10),
            text_color="#64748b", width=52).pack(side="left")
        _tex_opt = ctk.CTkOptionMenu(_res_row, variable=self.tex_res_var,
            values=["Full", "2048", "4096", "8192"],
            width=100, font=("Arial", 10),
            fg_color="#1e3a5a", button_color="#2a4f7a")
        _tex_opt.pack(side="left", padx=(0, 0))
        ToolTip(_tex_opt,
            "Sketchfab texture size: Full = native resolution.\n"
            "2048/4096/8192 = power-of-2 resize (Sketchfab max 8192×8192).")

        bf = ctk.CTkFrame(geo_f, fg_color="#0e1828", corner_radius=6)
        bf.pack(fill="x", padx=8, pady=(4, 6))
        ctk.CTkLabel(bf, text="Export Mesh:", font=("Arial", 10), text_color="#64748b").pack(anchor="w", padx=10, pady=(6, 2))
        _bf_row = ctk.CTkFrame(bf, fg_color="transparent"); _bf_row.pack(fill="x", padx=6, pady=(0, 4))
        _bf_row.grid_columnconfigure((0,1,2,3), weight=1)
        _btn_obj = ctk.CTkButton(_bf_row, text="OBJ / PLY", fg_color="#2980b9", height=32,
                                  command=lambda: self._export_3d('obj'))
        _btn_obj.grid(row=0, column=0, padx=3, sticky="ew")
        ToolTip(_btn_obj, "Export as OBJ (with optional PLY). Standard format for Blender, MeshLab, CloudCompare.")
        _btn_glb = ctk.CTkButton(_bf_row, text="GLB (Web)", fg_color="#7c3aed", height=32,
                                  command=lambda: self._export_3d('glb'))
        _btn_glb.grid(row=0, column=1, padx=3, sticky="ew")
        ToolTip(_btn_glb, "Export as binary GLB — compact format for Three.js, Sketchfab, and web viewers.")
        _btn_pc = ctk.CTkButton(_bf_row, text="Point Cloud", fg_color="#1a5276", height=32,
                                 command=lambda: self._export_3d('point'))
        _btn_pc.grid(row=0, column=2, padx=3, sticky="ew")
        ToolTip(_btn_pc, "Export as a PLY point cloud (no faces). Use in CloudCompare or for sparse processing.")
        _btn_e57 = ctk.CTkButton(_bf_row, text="E57", fg_color="#0e3a5a", height=32,
                                  command=self.export_e57)
        _btn_e57.grid(row=0, column=3, padx=3, sticky="ew")
        ToolTip(_btn_e57, "Export as E57 point cloud (ISO 19828).\n\nLeica Cyclone, FARO Scene, CloudCompare, HBIM.\nRequires: pip install pye57\nFalls back to binary PLY if pye57 is not installed.")
        self.requires_data_widgets.append(_btn_e57)

        # ── High-Detail Mesh option ───────────────────────────────────────────
        _hd_row = ctk.CTkFrame(bf, fg_color="#0a1520", corner_radius=4)
        _hd_row.pack(fill="x", padx=6, pady=(0, 6))
        # Row 1: checkbox (full width)
        _hd_chk_row = ctk.CTkFrame(_hd_row, fg_color="transparent")
        _hd_chk_row.pack(fill="x", padx=4, pady=(6, 2))
        self.hd_mesh_var = tk.BooleanVar(value=False)
        _hd_chk = ctk.CTkCheckBox(_hd_chk_row,
            text="High-Detail Mesh  (FC normals → Z, bypasses depth integration blur)",
            variable=self.hd_mesh_var,
            font=("Arial", 10), text_color="#7dd4f8",
            checkbox_width=16, checkbox_height=16)
        _hd_chk.pack(side="left", padx=(6, 0))
        ToolTip(_hd_chk,
            "When checked: uses Frankot-Chellappa integration of the PS normal\n"
            "map as the Z source instead of depth_vis_p.\n\n"
            "WHY: depth_vis_p is heavily HP-filtered (removes features <12mm).\n"
            "FC integration from normals retains full carved-line detail.\n"
            "Your medieval tile lettering, figure drapery, floral borders\n"
            "will all appear in the exported geometry.\n\n"
            "WHEN TO USE:\n"
            "  ✓ Carved stone, metal engraving, embossed leather, tiles\n"
            "  ✓ When the normal map looks great but the mesh looks smooth\n"
            "  ✓ For 3D printing or Blender detailed renders\n\n"
            "WHEN NOT TO USE:\n"
            "  ✗ Objects with strong macro warp (e.g. rolled parchment)\n"
            "    — use Macro Warp Removal slider to compensate\n"
            "  ✗ When you need the mesh to exactly match the 3D viewer")
        # Row 2: Warp slider (indented under checkbox)
        _hd_warp_row = ctk.CTkFrame(_hd_row, fg_color="transparent")
        _hd_warp_row.pack(fill="x", padx=4, pady=(0, 6))
        ctk.CTkLabel(_hd_warp_row, text="   Macro Warp σ%:", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.hd_warp_var = tk.DoubleVar(value=18.0)
        _hd_warp_sl = ctk.CTkSlider(_hd_warp_row, from_=0, to=50,
                                     variable=self.hd_warp_var, width=140)
        _hd_warp_sl.pack(side="left", padx=(4, 6))
        _hd_warp_lbl = ctk.CTkLabel(_hd_warp_row, text="18%", font=("Arial", 10),
                                     text_color="#f59e42", width=32)
        _hd_warp_lbl.pack(side="left")
        self.hd_warp_var.trace_add("write",
            lambda *_: _hd_warp_lbl.configure(text=f"{self.hd_warp_var.get():.0f}%"))
        ToolTip(_hd_warp_sl,
            "Removes broad surface tilt/warp from the FC depth result.\n"
            "Sigma is a percentage of the image diagonal.\n\n"
            "10–18% = good for flat objects (tiles, coins, flat leather)\n"
            "25–40% = use for objects with more curvature\n"
            "0% = no warp removal (raw FC result)")

        # ── STL Export (3D Print) ─────────────────────────────────────────────
        _stl_card = ctk.CTkFrame(bf, fg_color="#0e1a10", corner_radius=5)
        _stl_card.pack(fill="x", padx=6, pady=(0, 6))

        # Controls row
        _stl_ctrl = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _stl_ctrl.pack(fill="x", padx=8, pady=(6, 2))

        # Relief height slider
        ctk.CTkLabel(_stl_ctrl, text="Relief Height (mm):", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_relief_var = tk.DoubleVar(value=3.0)
        _stl_relief_sl = ctk.CTkSlider(_stl_ctrl, from_=0.5, to=30.0,
                                        variable=self.stl_relief_var, width=110)
        _stl_relief_sl.pack(side="left", padx=(4, 8))
        _stl_relief_lbl = ctk.CTkLabel(_stl_ctrl, text="3.0 mm", font=("Arial", 10),
                                        text_color="#f59e42", width=44)
        _stl_relief_lbl.pack(side="left")
        _stl_relief_sl.configure(command=lambda v: _stl_relief_lbl.configure(
            text=f"{float(v):.1f} mm"))
        ToolTip(_stl_relief_sl, "Maximum height of the surface relief above the base in mm.\n"
                "3 mm — first test.  5–8 mm — display models.\n"
                "10–20 mm — dramatic sculptural relief.\n"
                "Up to 30 mm for maximum depth effect.")

        # Base thickness slider
        _stl_ctrl2 = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _stl_ctrl2.pack(fill="x", padx=8, pady=(0, 2))
        ctk.CTkLabel(_stl_ctrl2, text="Base Thickness (mm):", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_base_var = tk.DoubleVar(value=3.0)
        _stl_base_sl = ctk.CTkSlider(_stl_ctrl2, from_=1.0, to=15.0,
                                      variable=self.stl_base_var, width=110)
        _stl_base_sl.pack(side="left", padx=(4, 8))
        _stl_base_lbl = ctk.CTkLabel(_stl_ctrl2, text="3.0 mm", font=("Arial", 10),
                                      text_color="#f59e42", width=44)
        _stl_base_lbl.pack(side="left")
        _stl_base_sl.configure(command=lambda v: _stl_base_lbl.configure(
            text=f"{float(v):.1f} mm"))
        ToolTip(_stl_base_sl, "Thickness of the solid base plate in mm.\n"
                "3 mm minimum recommended for print bed adhesion.\n"
                "Increase for larger/heavier models.")

        # Grid resolution slider
        _stl_ctrl3 = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _stl_ctrl3.pack(fill="x", padx=8, pady=(0, 2))
        ctk.CTkLabel(_stl_ctrl3, text="Grid Resolution (px):", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_res_var = tk.IntVar(value=200)
        _stl_res_sl = ctk.CTkSlider(_stl_ctrl3, from_=100, to=2500,
                                     variable=self.stl_res_var, width=110)
        _stl_res_sl.pack(side="left", padx=(4, 8))
        _stl_res_lbl = ctk.CTkLabel(_stl_ctrl3, text="200 px", font=("Arial", 10),
                                     text_color="#f59e42", width=54)
        _stl_res_lbl.pack(side="left")
        def _stl_res_update(v):
            px = int(float(v))
            mb = px * px * 6 * 50 // 1_000_000
            _stl_res_lbl.configure(text=f"{px} px (~{mb}MB)")
        _stl_res_sl.configure(command=_stl_res_update)
        ToolTip(_stl_res_sl,
            "Grid resolution — longest axis in pixels.\n\n"
            "FDM (Bambu X1C, Prusa):    200–300 px  •  ~6–15 MB  •  <30s\n"
            "MSLA (Elegoo Saturn/Mars):  600–900 px  •  ~50–120 MB  •  ~2 min\n"
            "SLA (Form 3/4, high detail): 1000–1500 px  •  ~150–350 MB  •  ~5 min\n"
            "Ultra-high detail (archival SLA): 2000–2500 px  •  ~600MB–1GB  •  ~15 min\n\n"
            "FDM XY resolution is ~0.1–0.4mm so 200 px across 256mm\n"
            "is already at the FDM detail limit.\n"
            "MSLA/SLA printers have 35–85 µm XY — use 600–1500 px\n"
            "to actually benefit from that precision.")

        # Print mode + mirror options row
        # ── Bed Size + Z Exaggeration row ─────────────────────────────────────
        _stl_ctrl4 = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _stl_ctrl4.pack(fill="x", padx=8, pady=(0, 2))

        # Bed size entry
        ctk.CTkLabel(_stl_ctrl4, text="Bed size (mm):", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_bed_var = tk.StringVar(value="256")
        _stl_bed_entry = ctk.CTkEntry(_stl_ctrl4, textvariable=self.stl_bed_var,
                                       width=52, font=("Arial", 10))
        _stl_bed_entry.pack(side="left", padx=(4, 12))
        ToolTip(_stl_bed_entry,
            "Long axis of your printer bed in mm.\n\n"
            "The model is scaled so its long dimension fills this.\n"
            "All Z (relief) dimensions remain in real mm — only XY is scaled.\n\n"
            "Bambu X1C / P1S : 256 mm\n"
            "Elegoo Saturn 4 : 218 mm\n"
            "Formlabs Form 4 : 200 mm\n"
            "Anycubic Photon : 165 mm\n\n"
            "Setting a smaller bed size does NOT reduce detail — the grid\n"
            "resolution is fixed by the slider above. Only XY spacing changes.")

        # Z Exaggeration slider
        ctk.CTkLabel(_stl_ctrl4, text="Z Exaggeration:", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_zex_var = tk.DoubleVar(value=1.0)
        _stl_zex_sl = ctk.CTkSlider(_stl_ctrl4, from_=1.0, to=10.0,
                                     variable=self.stl_zex_var, width=100)
        _stl_zex_sl.pack(side="left", padx=(4, 6))
        _stl_zex_lbl = ctk.CTkLabel(_stl_ctrl4, text="1.0×", font=("Arial", 10),
                                     text_color="#f59e42", width=36)
        _stl_zex_lbl.pack(side="left")
        _stl_zex_sl.configure(command=lambda v: _stl_zex_lbl.configure(
            text=f"{float(v):.1f}×"))
        ToolTip(_stl_zex_sl,
            "Multiply the relief Z height by this factor before export.\n\n"
            "Use this when scaling down to a smaller bed — without it, scaling\n"
            "XY down also crushes the Z relief and loses detail.\n\n"
            "Example: SLA bed = 200mm, model = 256mm → scale = 78%.\n"
            "Set Z Exaggeration to 1.3× to compensate for the 22% Z loss.\n\n"
            "1.0× = no exaggeration (physically accurate)\n"
            "2–3×  = subtle boost for fine inscriptions\n"
            "5–10× = dramatic sculptural effect\n\n"
            "Only the Z axis is multiplied — XY detail is unaffected.")

        # ── Printer preset + Mirror row ────────────────────────────────────────
        _stl_opts = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _stl_opts.pack(fill="x", padx=8, pady=(0, 4))

        # Printer presets — sets res + bed size together
        ctk.CTkLabel(_stl_opts, text="Preset:", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self.stl_printer_var = tk.StringVar(value="FDM")

        def _apply_printer_preset(v):
            if "FDM" in v:
                self.stl_res_var.set(200);  self.stl_bed_var.set("256")
            elif "MSLA" in v:
                self.stl_res_var.set(800);  self.stl_bed_var.set("218")
            else:  # SLA
                self.stl_res_var.set(1200); self.stl_bed_var.set("200")
            _stl_res_update(self.stl_res_var.get())

        _stl_printer_menu = ctk.CTkOptionMenu(
            _stl_opts, values=["FDM (Bambu/Prusa)", "MSLA (Elegoo/Anycubic)", "SLA (Form/Peopoly)"],
            variable=self.stl_printer_var, width=180, height=24,
            font=("Arial", 10), fg_color="#1a2a1a",
            command=_apply_printer_preset)
        _stl_printer_menu.pack(side="left", padx=(4, 12))
        ToolTip(_stl_printer_menu,
            "Quick preset — sets Grid Resolution and Bed Size together.\n\n"
            "FDM (Bambu X1C, Prusa):         200 px • 256mm bed\n"
            "MSLA (Elegoo Saturn, Anycubic): 800 px • 218mm bed\n"
            "SLA (Formlabs Form 4, Peopoly): 1200 px • 200mm bed\n\n"
            "Adjust Z Exaggeration if your inscriptions look too shallow\n"
            "after scaling down to a smaller bed.")

        # Mirror / flip checkbox
        self.stl_mirror_var = tk.BooleanVar(value=False)
        _stl_mirror_chk = ctk.CTkCheckBox(
            _stl_opts, text="Mirror X (fix reversed text)",
            variable=self.stl_mirror_var,
            font=("Arial", 10), text_color="#f59e42",
            checkbox_width=16, checkbox_height=16)
        _stl_mirror_chk.pack(side="left", padx=(0, 4))
        ToolTip(_stl_mirror_chk,
            "Mirrors the model left–right before export.\n\n"
            "Tick this if text or inscriptions appear reversed in your\n"
            "slicer (e.g. 'MISS' shows as 'SSIM').\n\n"
            "Flips the X axis of the depth grid only — relief is unaffected.")

        # Export button
        _bf_stl_btn = ctk.CTkFrame(_stl_card, fg_color="transparent")
        _bf_stl_btn.pack(fill="x", padx=8, pady=(2, 8))
        _btn_stl = ctk.CTkButton(_bf_stl_btn, text="🖨  Export STL for 3D Printing",
                                  fg_color="#1a5a2a", hover_color="#25803a",
                                  height=34, font=("Arial", 12, "bold"),
                                  command=self.export_stl_3dprint)
        _btn_stl.pack(fill="x")
        ToolTip(_btn_stl,
            "Export a watertight STL ready for your slicer.\n\n"
            "• Flat base at Z=0 — no floating geometry warnings\n"
            "• Side walls + bottom plate — fully watertight\n"
            "• Relief Height / Base Thickness set above\n"
            "• Grid Resolution matched to your printer type\n"
            "• Mirror X to fix reversed inscriptions if needed\n\n"
            "FDM: 200 px, <30s.   MSLA: 800 px, ~2 min.   SLA: 1200 px, ~5 min.")
        self.requires_data_widgets.append(_btn_stl)

        # ── Normal-Map Displacement Export ─────────────────────────────────────
        # Addresses the depth-integration detail loss: PS normals contain far more
        # surface detail than the integrated depth map. This exports a 16-bit
        # displacement TIFF + normal map + flat base mesh for use in Blender/ZBrush.
        _disp_card = ctk.CTkFrame(bf, fg_color="#0e1a20", corner_radius=5)
        _disp_card.pack(fill="x", padx=6, pady=(0, 8))

        _disp_hdr = ctk.CTkFrame(_disp_card, fg_color="transparent")
        _disp_hdr.pack(fill="x", padx=8, pady=(6, 2))
        ctk.CTkLabel(_disp_hdr, text="🔬 High-Detail Normal-Map Displacement",
                     font=("Arial", 10, "bold"), text_color="#7dd4f8").pack(side="left")

        # Collapsible info
        _disp_info_visible = tk.BooleanVar(value=False)
        _disp_info_frame = ctk.CTkFrame(_disp_card, fg_color="#061018", corner_radius=4)
        def _toggle_disp_info():
            if _disp_info_visible.get():
                _disp_info_frame.pack_forget()
                _disp_info_visible.set(False)
                _disp_info_btn.configure(text="ℹ Why use this?  ▾")
            else:
                _disp_info_frame.pack(fill="x", padx=8, pady=(0, 4))
                _disp_info_visible.set(True)
                _disp_info_btn.configure(text="ℹ Why use this?  ▴")
        _disp_info_btn = ctk.CTkButton(_disp_hdr, text="ℹ Why use this?  ▾",
                                        font=("Arial", 9), height=20, width=130,
                                        fg_color="#1a2a3a", hover_color="#2a3a4a",
                                        command=_toggle_disp_info)
        _disp_info_btn.pack(side="right")

        ctk.CTkLabel(_disp_info_frame,
            text=(
                "Why your 3D mesh looks smoother than your normal map:\n\n"
                "Depth integration (Poisson/FC) is a low-pass filter. It integrates\n"
                "surface slopes into heights — but fine carved lines (1–3px wide)\n"
                "don't accumulate enough slope over their width to survive integration.\n"
                "A 0.5mm deep carved groove in a tile may integrate to only 0.05mm.\n\n"
                "Your PS normal map captures the full surface orientation at every\n"
                "pixel. The solution is to use it directly as a displacement map\n"
                "in Blender, rather than relying solely on depth integration.\n\n"
                "Blender workflow (2 minutes):\n"
                "  1. Export this Displacement Package (button below)\n"
                "  2. In Blender: import the flat OBJ base mesh\n"
                "  3. Add Subdivision Surface modifier (level 7–8)\n"
                "  4. Add Displace modifier → use the 16-bit TIFF as texture\n"
                "  5. In Material: connect normal map PNG to Normal Map node\n"
                "  6. Set Displace strength = 0.05–0.2 (adjust to taste)\n"
                "  Result: full PS normal detail baked into geometry\n\n"
                "The 16-bit TIFF displacement is computed directly from the PS\n"
                "normals using Frankot-Chellappa integration with minimal smoothing,\n"
                "preserving detail that Poisson integration would lose."
            ),
            font=("Courier", 9), text_color="#94a3b8",
            justify="left", anchor="w", wraplength=340).pack(padx=10, pady=8, anchor="w")

        _disp_ctrl = ctk.CTkFrame(_disp_card, fg_color="transparent")
        _disp_ctrl.pack(fill="x", padx=8, pady=(2, 4))
        ctk.CTkLabel(_disp_ctrl, text="Base mesh step:", font=("Arial", 10),
                     text_color="#94a3b8").pack(side="left")
        self._disp_step_var = tk.IntVar(value=4)
        ctk.CTkOptionMenu(_disp_ctrl, values=["2","4","6","8"],
                          width=60, height=22, font=("Arial", 10),
                          variable=tk.StringVar(value="4"),
                          command=lambda v: self._disp_step_var.set(int(v)),
                          fg_color="#1a2a3a").pack(side="left", padx=(4, 12))
        ToolTip(_disp_ctrl,
            "Resolution of the flat base mesh (step = pixels between vertices).\n"
            "Step 4 = medium base mesh (~1M verts at 4K resolution) — good default.\n"
            "Step 2 = dense base mesh — larger file, marginally better macro shape.\n"
            "Step 6–8 = coarse base — use when the displacement does all the work.")

        _disp_btn = ctk.CTkButton(_disp_card,
            text="📦  Export Displacement Package  (OBJ + 16-bit Displacement + Normal Map)",
            fg_color="#0e3a5a", hover_color="#1a5276", height=30,
            font=("Arial", 10, "bold"),
            command=self.export_displacement_package)
        _disp_btn.pack(fill="x", padx=8, pady=(2, 8))
        ToolTip(_disp_btn,
            "Exports a folder containing:\n\n"
            "  flat_base.obj  — coarse mesh capturing macro tile warp only\n"
            "  displacement_16bit.tif — 16-bit greyscale displacement map\n"
            "                          derived from PS normals via FC integration\n"
            "                          with minimal smoothing (preserves fine detail)\n"
            "  normal_map.png — RGB normal map for Blender material\n"
            "  albedo.png     — colour texture\n"
            "  README.txt     — step-by-step Blender import guide\n\n"
            "Use in Blender: import flat_base.obj → Subdivision modifier\n"
            "→ Displace modifier with displacement_16bit.tif\n"
            "→ Normal Map node in material with normal_map.png.\n"
            "Gives full PS detail in geometry without depth integration blur.")
        self.requires_data_widgets.append(_disp_btn)
        # _TAB_HINTS must be defined before _tab_hdr_row references it
        _TAB_HINTS = {
            "2D Renders":   "Export renders & reports.  [S] Snapshot TIFF  ·  [G] GIF animation  ·  [E] Cycle engine fwd  ·  [⇧E] Cycle back  ·  [A] Light sweep  ·  [H] Histogram  ·  [F] Fit view  ·  [?] All shortcuts",
            "3D & Web":     "3D viewer & exports.  [⌘3] Open 3D viewer  ·  [⌘E] Export TIFF  ·  [R] in viewer: reset camera  ·  [S] in viewer: screenshot (up to 20)  ·  Double-click: re-centre",
            "Metrology":    "Calibrated measurement.  Set PPI first via sphere calibration, then extract Z-profiles and ISO 25178 surface parameters (Sa, Sq, Ra, Rq).",
            "AI Tools":     "AI image analysis.  Paste API key → choose provider → Analyse.  Works on current rendered view.",
            "Archive":      "Heritage metadata & deposits.  Fill Object ID (left panel) first.  Exports IIIF v3, MorphoSource, Zenodo, Dublin Core TIFF.",
        }

        # ── Hint strip + ❓ Help — packed before tab_view so it sits above tabs ─
        _tab_hdr_row = ctk.CTkFrame(_exports_body, fg_color="transparent")
