        tab_view.pack(fill="both", expand=True, padx=6, pady=(0, 6))
        for tab_name in ["2D Renders", "3D & Web", "Metrology", "AI Tools", "Archive"]:
            tab_view.add(tab_name)

        def _on_tab_change():
            tab = tab_view.get()
            _hint_strip.configure(text=_TAB_HINTS.get(tab, ""))
            # update the ? button's stored tab name
            _help_tab_var.set(tab)
        tab_view.configure(command=_on_tab_change)

        # ── tab_btn: single factory for all tab buttons ─────────────────────
        # Uniform height=30, font=("Arial",11), consistent padding everywhere.
        # Hover colour auto-derived from fg_color by CTk internals.
        def tab_btn(tab, text, cmd, color="#4a6984", tip="", row=None, col=None, span=1):
            parent = tab_view.tab(tab)
            btn = ctk.CTkButton(parent, text=text, fg_color=color, command=cmd,
                                height=30, font=("Arial", 11),
                                border_width=0, corner_radius=5)
            if row is not None:
                if not hasattr(parent, '_gc'):
                    parent.grid_columnconfigure(0, weight=1)
                    parent.grid_columnconfigure(1, weight=1)
                    parent._gc = True
                btn.grid(row=row, column=col, columnspan=span, padx=4, pady=3, sticky="ew")
            else:
                btn.pack(fill="x", padx=6, pady=3)
            self.requires_data_widgets.append(btn)
            if tip:
                ToolTip(btn, tip)
            return btn

