        tab_btn("2D Renders", "✏️  Annotation Layer",         self.open_annotation_layer,        "#5b4a8a", "Draw arrows, labels and measurements directly on the render.\nExports as SVG overlay for publication figures.", 9, 0, span=2)
        tab_btn("2D Renders", "🪞 Mirror / Invert Render",    self.open_mirror_invert_panel,     "#5a3a2a", "Flip, mirror and invert the render for printing plate analysis.\nHorizontal flip, vertical flip, 180° rotation, depth inversion.\nEssential for engraved plates, seals and impression tools.", 10, 0, span=2)
        # Forensic Spectral Analysis is in the Forensic tab — button removed from here to avoid duplication
