        _rvt_hs_use_sfs_cb.pack(side="left", padx=(0,16))
        ToolTip(_rvt_hs_use_sfs_cb, "When checked, uses the az/alt/Z-factor set in the SFS panel above.\n"
            "Uncheck to use independent hillshade parameters for the RVT layers.")

        def _rvt_hs_toggle(*_):
            state = "normal" if not self._rvt_hs_use_sfs_var.get() else "disabled"
            for _w in [_rvt_hs_az_sl, _rvt_hs_alt_sl, _rvt_hs_z_sl]:
                _w.configure(state=state)
        self._rvt_hs_use_sfs_var.trace_add("write", _rvt_hs_toggle)

        ctk.CTkLabel(_rvt_hs_param_row, text="Az:", font=("Arial", 9),
                     text_color="#7ec8e3", width=22).pack(side="left")
        self._rvt_hs_az_var = tk.DoubleVar(value=305.0)
        _rvt_hs_az_sl = ctk.CTkSlider(_rvt_hs_param_row, from_=0.0, to=359.0,
                         variable=self._rvt_hs_az_var, width=90, state="disabled",
                         button_color="#7ec8e3", progress_color="#1a3a4a")
        _rvt_hs_az_sl.pack(side="left", padx=(3,3))
        _rvt_hs_az_lbl = ctk.CTkLabel(_rvt_hs_param_row, text="305°", font=("Arial", 9),
                                        text_color="#7ec8e3", width=34)
