        _rvt_hs_alt_sl = ctk.CTkSlider(_rvt_hs_param_row, from_=5.0, to=85.0,
                          variable=self._rvt_hs_alt_var, width=80, state="disabled",
                          button_color="#7ec8e3", progress_color="#1a3a4a")
        _rvt_hs_alt_sl.pack(side="left", padx=(3,3))
        _rvt_hs_alt_lbl = ctk.CTkLabel(_rvt_hs_param_row, text="45°", font=("Arial", 9),
                                         text_color="#7ec8e3", width=30)
        _rvt_hs_alt_lbl.pack(side="left")
