    def export_ptm_coeffs(self):
        """Export PTM polynomial coefficient maps with optional colour previews."""
        if getattr(self, 'ptm_coeffs', None) is None:
            messagebox.showwarning("PTM Export", "No PTM coefficients — process images first."); return

        # ── Options dialogue ──────────────────────────────────────────────────
        dlg = ctk.CTkToplevel(self); dlg.title("PTM Coefficient Export Options")
        dlg.geometry("400x260"); dlg.grab_set(); dlg.attributes("-topmost", True)
        ctk.CTkLabel(dlg, text="PTM Coefficient Export",
                     font=("Arial", 14, "bold"), text_color="#7ec8e3").pack(pady=(16,4))
        ctk.CTkLabel(dlg, text="Select which file formats to export:",
                     font=("Arial", 11), text_color="#aabbcc").pack(pady=(0,10))
        _f32_var = tk.BooleanVar(value=True)
        _u16_var = tk.BooleanVar(value=True)
        _vis_var = tk.BooleanVar(value=False)
        ctk.CTkCheckBox(dlg, text="Float32 TIF  (_f32.tif) — full precision, for relighting tools",
                        variable=_f32_var, font=("Arial", 11)).pack(anchor="w", padx=24, pady=2)
        ctk.CTkCheckBox(dlg, text="16-bit TIF   (_u16.tif) — range-mapped, preserves sign",
                        variable=_u16_var, font=("Arial", 11)).pack(anchor="w", padx=24, pady=2)
        ctk.CTkCheckBox(dlg, text="Colour preview (_vis.tif) — 8-bit TURBO false-colour",
                        variable=_vis_var, font=("Arial", 11),
                        text_color="#f0c060").pack(anchor="w", padx=24, pady=2)
        ctk.CTkLabel(dlg, text="6 coefficients × selected formats will be written.",
                     font=("Arial", 9), text_color="#5577aa").pack(pady=(6,0))
        _result = [False]
        def _ok():
            _result[0] = True; dlg.grab_release(); dlg.destroy()
        def _cancel():
            dlg.grab_release(); dlg.destroy()
        _br = ctk.CTkFrame(dlg, fg_color="transparent"); _br.pack(pady=12)
        ctk.CTkButton(_br, text="Export", fg_color="#1a4a2a", width=100, command=_ok).pack(side="left", padx=6)
        ctk.CTkButton(_br, text="Cancel", fg_color="#3a3a4a", width=80, command=_cancel).pack(side="left", padx=6)
        self.wait_window(dlg)
        if not _result[0]: return

        f = filedialog.askdirectory(title="Select Output Directory for PTM Maps")
        if not f: return
        do_f32, do_u16, do_vis = _f32_var.get(), _u16_var.get(), _vis_var.get()
        if not any([do_f32, do_u16, do_vis]):
            messagebox.showinfo("PTM Export", "Nothing selected — no files written."); return
        try:
            saved = 0
            for i in range(6):
                _c = self.ptm_coeffs[i].reshape(self.h, self.w).astype(np.float32)
                if do_f32:
                    cv2.imwrite(os.path.join(f, f"ptm_coeff_{i}_f32.tif"), _c,
                                [cv2.IMWRITE_TIFF_COMPRESSION, 1]); saved += 1
                if do_u16:
                    _mn, _mx = float(_c.min()), float(_c.max())
                    _u16 = ((_c - _mn) / max(_mx-_mn, 1e-9) * 65535).astype(np.uint16)
                    cv2.imwrite(os.path.join(f, f"ptm_coeff_{i}_u16.tif"), _u16,
                                [cv2.IMWRITE_TIFF_COMPRESSION, 1]); saved += 1
                if do_vis:
                    _u8 = cv2.normalize(_c, None, 0, 255, cv2.NORM_MINMAX).astype(np.uint8)
                    cv2.imwrite(os.path.join(f, f"ptm_coeff_{i}_vis.tif"),
                                cv2.applyColorMap(_u8, cv2.COLORMAP_TURBO),
                                [cv2.IMWRITE_TIFF_COMPRESSION, 1]); saved += 1
            parts = []
            if do_f32: parts.append("_f32.tif  — float32 full precision")
            if do_u16: parts.append("_u16.tif  — 16-bit range-mapped")
            if do_vis: parts.append("_vis.tif  — 8-bit false-colour")
            messagebox.showinfo("PTM Export",
                f"{saved} files saved to:\n{f}\n\n" + "\n".join(parts))
        except Exception as e:
            messagebox.showerror("PTM Export Error", str(e))

