    def open_neural_rti_viewer(self):
        '''HSH Hemispherical Harmonics relighting (Mudge et al. 2008).
        Per pixel: I(L)=sum_k c_k*h_k(lx,ly), 9 HSH basis functions.
        Fitting: C=pinv(B^T B) B^T I  vectorised over all pixels.
        Ref: Ponchio et al. 2024 neural extension, dl.acm.org/doi/10.1145/3690390.'''
        if getattr(self,'normals_full',None) is None or not getattr(self,'plate_paths',[]):
            messagebox.showwarning('Neural RTI','Process scans first.'); return
        if getattr(self,'current_L_mat',None) is None:
            messagebox.showwarning('Neural RTI',
                'No light matrix.\nLoad LP file or run processing first.'); return
        import threading
        def _fit():
            try:
                H,W = self.normals_full.shape[:2]
                sc  = min(1.0, 900/max(H,W))
                ph,pw = int(H*sc), int(W*sc)
                imgs = []
                for p in self.plate_paths:
                    g = cv2.imread(p, cv2.IMREAD_GRAYSCALE)
                    if g is None: continue
                    if g.shape[:2]!=(H,W): g=cv2.resize(g,(W,H))
                    imgs.append(cv2.resize(g,(pw,ph)).astype(np.float32)/255.0)
                if len(imgs)<4:
                    self.after(0,lambda:messagebox.showerror('RTI','Need >= 4 images.')); return
                N  = len(imgs)
                L  = self.current_L_mat[:N]
                lx,ly = L[:,0].astype(np.float64), L[:,1].astype(np.float64)
                lz = np.sqrt(np.clip(1.0-lx**2-ly**2,0.0,1.0))
                B  = np.column_stack([np.ones(N),lx,ly,lx*ly,
                                      lx**2-ly**2,lz,lz*lx,lz*ly,(3*lz**2-1)/2])
                Imat = np.stack(imgs,axis=0).reshape(N,-1)
                C = (np.linalg.pinv(B.T@B)@B.T@Imat).reshape(9,ph,pw).astype(np.float32)
                self.rti_coeffs = C
                self.after(0,lambda: self._show_rti_viewer(C,ph,pw))
            except Exception as e:
                self.after(0,lambda: messagebox.showerror('RTI Error',str(e)))
        threading.Thread(target=_fit,daemon=True).start()
        messagebox.showinfo('Neural RTI',
            'Fitting HSH model in background...\nViewer opens when ready.')

    def _show_rti_viewer(self, C, ph, pw):
        '''Interactive HSH relighting viewer -- drag image to move light.'''
        win=tk.Toplevel(self); win.title('Neural RTI -- HSH Relighting')
        win.configure(bg='#0e1520'); win.geometry(f'{pw+220}x{ph+40}')
        win.resizable(False,False)
        canvas=tk.Canvas(win,width=pw,height=ph,bg='#0e1520',highlightthickness=0)
        canvas.pack(side='left')
        rp=tk.Frame(win,bg='#0e1520',width=210); rp.pack(side='right',fill='y',padx=8)
        tk.Label(rp,text='Neural RTI',bg='#0e1520',fg='#88bbdd',
                 font=('Arial',11,'bold')).pack(pady=(12,2))
        tk.Label(rp,text='Drag image to move light',bg='#0e1520',
                 fg='#6688aa',font=('Arial',8)).pack()
        dc=tk.Canvas(rp,width=100,height=100,bg='#0e1520',highlightthickness=0)
        dc.pack(pady=8); dc.create_oval(5,5,95,95,outline='#334455',width=2)
        lbl_lx=tk.Label(rp,text='lx:  0.000',bg='#0e1520',fg='#aabbcc',font=('Arial',8))
        lbl_lx.pack()
        lbl_ly=tk.Label(rp,text='ly:  0.000',bg='#0e1520',fg='#aabbcc',font=('Arial',8))
        lbl_ly.pack()
        _ir=[None]
        def _relight(lx,ly):
            lz_=float(np.sqrt(max(0.0,1.0-lx**2-ly**2)))
            h=np.array([1,lx,ly,lx*ly,lx**2-ly**2,lz_,lz_*lx,lz_*ly,
                        (3*lz_**2-1)/2],dtype=np.float32)
            relit=np.einsum('k,khw->hw',h,C).clip(0,1)
            img8=(relit*255).astype(np.uint8)
            try:
                from PIL import Image,ImageTk
                pil=Image.fromarray(img8,'L').convert('RGB')
                _ir[0]=ImageTk.PhotoImage(pil)
                canvas.delete('all')
                canvas.create_image(0,0,anchor='nw',image=_ir[0])
            except ImportError: pass
            dxc,dyc=int(50+lx*44),int(50-ly*44)
            dc.delete('lt')
            dc.create_oval(dxc-6,dyc-6,dxc+6,dyc+6,fill='#ffcc44',outline='',tags='lt')
            lbl_lx.config(text=f'lx: {lx:+.3f}'); lbl_ly.config(text=f'ly: {ly:+.3f}')
        def _drag(ev):
            lx=float(np.clip((ev.x/pw)*2-1,-0.95,0.95))
            ly=float(np.clip(-((ev.y/ph)*2-1),-0.95,0.95))
            _relight(lx,ly)
        canvas.bind('<B1-Motion>',_drag); canvas.bind('<Button-1>',_drag)
        def _save():
            lz_=float(np.sqrt(max(0.0,1.0)))
            h=np.array([1,0,0,0,0,lz_,0,0,(3*lz_**2-1)/2],dtype=np.float32)
            relit=np.einsum('k,khw->hw',h,C).clip(0,1)
            fp=filedialog.asksaveasfilename(defaultextension='.png',
               filetypes=[('PNG','*.png'),('TIFF','*.tif')],title='Save RTI Frame')
            if fp: cv2.imwrite(fp,(relit*255).astype(np.uint8))
        tk.Button(rp,text='Save Frame',command=_save,bg='#1a3a5a',fg='white',
                  relief='flat',font=('Arial',9,'bold')).pack(pady=(16,4),fill='x',padx=4)
        tk.Button(rp,text='Close',command=win.destroy,bg='#3a1a1a',fg='white',
                  relief='flat',font=('Arial',9)).pack(pady=4,fill='x',padx=4)
        _relight(0.0,0.0)


    def export_hillshades_32bit(self):
        f = filedialog.askdirectory()
        if not f: return
        try:
            # V50: respect depth inversion if active
            _dp  = self._v50_get_depth('poisson')
            _dfc = self._v50_get_depth('fc')
            _dvp = self._v50_get_depth('vis_p')
            _dvfc= self._v50_get_depth('vis_fc')
            maps_to_save = {
                "1_height_map_primary_32f.tif": _dp.astype(np.float32), "2_height_map_FC_32f.tif": _dfc.astype(np.float32),
                "3_hillshade_primary_32f.tif": self.calc_hillshade_raw(_dvp, self.engine_settings.get("PS Normal-Map Lit (Single)", self.engine_settings["Standard PBR"])).astype(np.float32),
                "4_hillshade_FC_32f.tif": self.calc_hillshade_raw(_dvfc, self.engine_settings.get("PS Normal-Map Lit (Single)", self.engine_settings["Standard PBR"])).astype(np.float32),
                "5_multi_directional_hillshade_32f.tif": self.calc_multi_hillshade(_dvp, self.engine_settings.get("PS Normal-Map Lit (8-Dir)", self.engine_settings["Standard PBR"])).astype(np.float32),
                "6_sky_view_factor_32f.tif": self.calc_svf(_dvp, self.engine_settings.get("Sky-View Factor (SVF)", self.engine_settings["Standard PBR"])).astype(np.float32)
            }
            if HAS_RASTERIO:
                res_mm = 1.0 
                try:
                    if float(self.scale_mm.get()) > 0 and getattr(self, 'drawn_scale_px', None): res_mm = float(self.scale_mm.get()) / self.drawn_scale_px
                except: pass
                _res_m = res_mm / 1000.0   # kept for metadata only
                # Pixel size = 1.0 so QGIS RVT search radii work as cell counts,
                # not as enormous sub-mm fractions.
                transform = from_origin(0, float(self.h), 1.0, 1.0)
                for name, data in maps_to_save.items():
                    with rasterio.open(os.path.join(f, name), 'w', driver='GTiff', height=self.h, width=self.w, count=1, dtype='float32', crs='EPSG:32630', transform=transform) as dst: dst.write(data, 1)
            else:
                for name, data in maps_to_save.items(): cv2.imwrite(os.path.join(f, name), data, [cv2.IMWRITE_TIFF_COMPRESSION, 1])
            messagebox.showinfo("Export", "32-bit Float Maps Saved.")
        except Exception as e: messagebox.showerror("Error", str(e))

    def open_rvt_terrain_panel(self):
        """RVT-style terrain analysis panel with vertical exaggeration and depth source control."""
        if getattr(self, 'depth_vis_p', None) is None:
            messagebox.showwarning("Terrain Analysis", "Process scans first."); return

        win = ctk.CTkToplevel(self)
        win.title("Terrain Analysis — RVT Style")
        win.geometry("660x900")
        win.attributes("-topmost", True)
        win.after(400, lambda: win.attributes("-topmost", False))

        ctk.CTkLabel(win, text="Terrain Analysis",
                     font=("Arial", 15, "bold"), text_color="#4ade80").pack(pady=(14,2))
        ctk.CTkLabel(win,
                     text="Tick analyses to compute, set parameters, then click Compute.",
                     font=("Arial", 10), text_color="#8899aa").pack(pady=(0,6))

        # ── Global settings bar ───────────────────────────────────────────────
        _gbar = ctk.CTkFrame(win, fg_color="#0a1a10", corner_radius=6)
        _gbar.pack(fill="x", padx=14, pady=(0,6))

        # Depth source (like the SFS dropdown)
        _src_row = ctk.CTkFrame(_gbar, fg_color="transparent"); _src_row.pack(fill="x", padx=10, pady=(8,4))
        ctk.CTkLabel(_src_row, text="Depth source:", font=("Arial",10), text_color="#aabbcc",
                     width=100, anchor="w").pack(side="left")
        _depth_src_var = tk.StringVar(value="Standard (depth_vis_p)")
        ctk.CTkOptionMenu(_src_row,
                          values=["Standard (depth_vis_p)",
                                  "Frankot-Chellappa (depth_vis_fc)",
                                  "High-Freq (HF — medium features)",
                                  "Ultra-High-Freq (UHF — scratches/grain)"],
                          variable=_depth_src_var,
                          width=320, font=("Arial", 10),
                          fg_color="#1a2a1a", button_color="#2a4a2a"
                          ).pack(side="left", padx=(6,0))
        ToolTip(_src_row,
                "Standard: Poisson-integrated depth — best for general relief.\n"
                "Frankot-Chellappa: alternative integration, reduces edge ringing.\n"
                "High-Freq: Gaussian high-pass sigma=5% image size — medium features.\n"
                "Ultra-High-Freq: sigma=0.5% — finest scratches and grain only.")

        # Vertical Exaggeration Factor
        _ve_row = ctk.CTkFrame(_gbar, fg_color="transparent"); _ve_row.pack(fill="x", padx=10, pady=(0,4))
        ctk.CTkLabel(_ve_row, text="Vertical exaggeration:", font=("Arial",10),
                     text_color="#f39c12", width=160, anchor="w").pack(side="left")
        _ve_var = tk.DoubleVar(value=5.0)
        _ve_lbl = ctk.CTkLabel(_ve_row, text="5.0", font=("Arial",10,"bold"),
                                text_color="#f39c12", width=40)
        def _ve_upd(v): _ve_lbl.configure(text=f"{float(v):.1f}")
        ctk.CTkSlider(_ve_row, from_=0.5, to=50.0, variable=_ve_var,
                      number_of_steps=99, command=_ve_upd,
                      button_color="#f39c12", button_hover_color="#e67e22"
                      ).pack(side="left", fill="x", expand=True, padx=6)
        _ve_lbl.pack(side="left")
        ToolTip(_ve_row,
                "Vertical Exaggeration Factor (identical to QGIS RVT).\n\n"
                "Scales the depth map before computing slope, hillshade, SVF etc.\n"
                "Manuscripts/book covers: 3–10 reveals subtle tooling and embossing.\n"
                "Coins/medals: 1–3 is usually enough (higher relief).\n"
                "Parchment micro-texture: 15–50 for very shallow scratches.")

        # Output format
        _fmt_row = ctk.CTkFrame(_gbar, fg_color="transparent"); _fmt_row.pack(fill="x", padx=10, pady=(0,8))
        ctk.CTkLabel(_fmt_row, text="Output format:", font=("Arial",10),
                     text_color="#aabbcc", width=100, anchor="w").pack(side="left")
        _fmt_tif = tk.BooleanVar(value=True)
        _fmt_jpg = tk.BooleanVar(value=False)
        ctk.CTkCheckBox(_fmt_row, text="32-bit GeoTIFF", variable=_fmt_tif,
                        font=("Arial",10), width=130).pack(side="left", padx=4)
        ctk.CTkCheckBox(_fmt_row, text="JPEG (8-bit preview)", variable=_fmt_jpg,
                        font=("Arial",10), width=160).pack(side="left", padx=4)
        ToolTip(_fmt_row,
                "32-bit GeoTIFF: full precision float32 — for GIS analysis in QGIS.\n"
                "JPEG: 8-bit normalized preview — for quick sharing or Photoshop overlay.")

        # ── Scrollable analysis sections ──────────────────────────────────────
        sf = ctk.CTkScrollableFrame(win, height=600); sf.pack(fill="both", expand=True, padx=12)

        def _section(title, colour="#4a8a5a"):
            hdr = ctk.CTkFrame(sf, fg_color="#0d1f12", corner_radius=5)
            hdr.pack(fill="x", pady=(8,0))
            v = tk.BooleanVar(value=False)
            ctk.CTkCheckBox(hdr, text=title, variable=v, font=("Arial", 11, "bold"),
                            text_color=colour, width=560).pack(side="left", padx=10, pady=6)
            body = ctk.CTkFrame(sf, fg_color="#0a1510", corner_radius=4)
            body.pack(fill="x", pady=(0,2))
            return v, body

        def _row(parent, label, var, from_, to, default, unit="", fmt="{:.0f}"):
            r = ctk.CTkFrame(parent, fg_color="transparent"); r.pack(fill="x", padx=12, pady=2)
            ctk.CTkLabel(r, text=label, font=("Arial", 10), text_color="#94a3b8",
                         width=190, anchor="w").pack(side="left")
            _lbl = ctk.CTkLabel(r, text=fmt.format(default)+(" "+unit if unit else ""),
                                font=("Arial", 10, "bold"), text_color="#f59e42", width=60)
            def _upd(v): _lbl.configure(text=fmt.format(float(v))+(" "+unit if unit else ""))
            ctk.CTkSlider(r, from_=from_, to=to, variable=var, command=_upd
                          ).pack(side="left", fill="x", expand=True, padx=6)
            _lbl.pack(side="left")

        v_hs, b_hs = _section("Hillshade")
        _hs_azi = tk.DoubleVar(value=315); _hs_alt = tk.DoubleVar(value=35)
        _hs_shadow = tk.BooleanVar(value=False)
        _row(b_hs, "Sun azimuth [deg]:", _hs_azi, 0, 360, 315, "°")
        _row(b_hs, "Sun elevation [deg]:", _hs_alt, 1, 90, 35, "°")
        _sh = ctk.CTkFrame(b_hs, fg_color="transparent"); _sh.pack(fill="x", padx=12, pady=(0,6))
        ctk.CTkCheckBox(_sh, text="Shadow modelling (binary)",
                        variable=_hs_shadow, font=("Arial",10)).pack(side="left")

        v_mhs, b_mhs = _section("Hillshade from multiple directions")
        _mhs_n = tk.IntVar(value=8); _mhs_alt = tk.DoubleVar(value=35)
        _row(b_mhs, "Number of directions:", _mhs_n, 4, 32, 8)
        _row(b_mhs, "Sun elevation [deg]:", _mhs_alt, 1, 90, 35, "°")
        ctk.CTkLabel(b_mhs, text="", height=4).pack()

        v_sl, b_sl = _section("Slope gradient")
        _sl_unit = tk.StringVar(value="degree")
        _sl_r = ctk.CTkFrame(b_sl, fg_color="transparent"); _sl_r.pack(fill="x", padx=12, pady=6)
        ctk.CTkLabel(_sl_r, text="Output unit:", font=("Arial",10),
                     text_color="#94a3b8", width=120).pack(side="left")
        ctk.CTkOptionMenu(_sl_r, values=["degree","percent","radian"],
                          variable=_sl_unit, width=120, font=("Arial",10)).pack(side="left")

        v_slrm, b_slrm = _section("Simple Local Relief Model (SLRM)")
        _slrm_r = tk.IntVar(value=20)
        _row(b_slrm, "Radius [pixels]:", _slrm_r, 5, 100, 20, "px")
        ctk.CTkLabel(b_slrm, text="", height=4).pack()

        v_msrm, b_msrm = _section("Multi-Scale Relief Model (MSRM)")
        _msrm_min = tk.DoubleVar(value=1.0); _msrm_max = tk.DoubleVar(value=20.0)
        _msrm_sc  = tk.IntVar(value=2)
        _row(b_msrm, "Feature minimum [px]:", _msrm_min, 0, 20, 1, "px", "{:.1f}")
        _row(b_msrm, "Feature maximum [px]:", _msrm_max, 2, 60, 20, "px", "{:.1f}")
        _row(b_msrm, "Scaling factor:", _msrm_sc, 1, 8, 2)
        ctk.CTkLabel(b_msrm, text="", height=4).pack()

        v_svf, b_svf = _section("Sky-View Factor (SVF)")
        _svf_r = tk.IntVar(value=20); _svf_d = tk.IntVar(value=16)
        _row(b_svf, "Search radius [pixels]:", _svf_r, 5, 50, 20, "px")
        _row(b_svf, "Search directions:", _svf_d, 4, 32, 16)
        ctk.CTkLabel(b_svf, text="", height=4).pack()

        v_asvf, b_asvf = _section("Anisotropic Sky-View Factor (A-SVF)")
        _asvf_az = tk.DoubleVar(value=315); _asvf_aniso = tk.StringVar(value="low")
        _a1 = ctk.CTkFrame(b_asvf, fg_color="transparent"); _a1.pack(fill="x", padx=12, pady=4)
        ctk.CTkLabel(_a1, text="Level of anisotropy:", font=("Arial",10),
                     text_color="#94a3b8", width=160).pack(side="left")
        ctk.CTkOptionMenu(_a1, values=["low","high"], variable=_asvf_aniso,
                          width=80, font=("Arial",10)).pack(side="left")
        _row(b_asvf, "Main direction [deg]:", _asvf_az, 0, 360, 315, "°")
        ctk.CTkLabel(b_asvf, text="", height=4).pack()

        v_po, b_po = _section("Openness — Positive")
        _po_r = tk.IntVar(value=20)
        _row(b_po, "Search radius [pixels]:", _po_r, 5, 50, 20, "px")
        ctk.CTkLabel(b_po, text="Uses same search directions as SVF.", height=24,
                     font=("Arial",9), text_color="#4a6a5a").pack(anchor="w", padx=14)

        v_no, b_no = _section("Openness — Negative")
        ctk.CTkLabel(b_no,
                     text="Uses same radius and directions as Positive Openness.",
                     height=26, font=("Arial",9), text_color="#4a6a5a"
                     ).pack(anchor="w", padx=14, pady=4)

        v_ld, b_ld = _section("Local Dominance")
        _ld_min = tk.IntVar(value=10); _ld_max = tk.IntVar(value=20)
        _row(b_ld, "Minimum radius [px]:", _ld_min, 5, 50, 10, "px")
        _row(b_ld, "Maximum radius [px]:", _ld_max, 10, 100, 20, "px")
        ctk.CTkLabel(b_ld, text="", height=4).pack()

        v_cv, b_cv = _section("Surface Curvature")
        ctk.CTkLabel(b_cv,
                     text="Laplacian of depth — highlights edges and fine surface detail.",
                     height=26, font=("Arial",9), text_color="#4a6a5a"
                     ).pack(anchor="w", padx=14, pady=4)

        # ── Bottom bar ────────────────────────────────────────────────────────
        _bot = ctk.CTkFrame(win, fg_color="transparent"); _bot.pack(fill="x", padx=14, pady=8)

        _save_var = tk.BooleanVar(value=True)
        ctk.CTkCheckBox(_bot, text="Save outputs", variable=_save_var,
                        font=("Arial",10)).pack(side="left", padx=4)

        def _all_on():
            for v in [v_hs,v_mhs,v_sl,v_slrm,v_msrm,v_svf,v_asvf,v_po,v_no,v_ld,v_cv]:
                v.set(True)
        def _all_off():
            for v in [v_hs,v_mhs,v_sl,v_slrm,v_msrm,v_svf,v_asvf,v_po,v_no,v_ld,v_cv]:
                v.set(False)
        ctk.CTkButton(_bot, text="All",  width=50, height=26, fg_color="#1a3a2a",
                      command=_all_on).pack(side="left", padx=2)
        ctk.CTkButton(_bot, text="None", width=50, height=26, fg_color="#3a2a1a",
                      command=_all_off).pack(side="left", padx=2)

        def _compute():
            tasks = []
            if v_hs.get():
                tasks.append(("Hillshade", {"hs_azi":_hs_azi.get(),"hs_alt":_hs_alt.get(),
                                             "shadow":_hs_shadow.get()}))
            if v_mhs.get():
                tasks.append(("Multi-Dir Hillshade",
                               {"n_dirs":_mhs_n.get(),"hs_alt":_mhs_alt.get()}))
            if v_sl.get():
                tasks.append(("Slope Gradient", {"unit":_sl_unit.get()}))
            if v_slrm.get():
                tasks.append(("SLRM", {"radius":_slrm_r.get()}))
            if v_msrm.get():
                tasks.append(("MSRM", {"msrm_min":float(_msrm_min.get()),
                                        "msrm_max":float(_msrm_max.get()),
                                        "msrm_scale":_msrm_sc.get()}))
            if v_svf.get():
                tasks.append(("SVF", {"svf_radius":_svf_r.get(),"svf_dirs":_svf_d.get()}))
            if v_asvf.get():
                tasks.append(("Anisotropic SVF",
                               {"svf_radius":_svf_r.get(),"svf_dirs":_svf_d.get(),
                                "aniso":_asvf_aniso.get(),"hs_azi":_asvf_az.get()}))
            if v_po.get():
                tasks.append(("Positive Openness",
                               {"op_radius":_po_r.get(),"svf_dirs":_svf_d.get()}))
            if v_no.get():
                tasks.append(("Negative Openness",
                               {"op_radius":_po_r.get(),"svf_dirs":_svf_d.get()}))
            if v_ld.get():
                tasks.append(("Local Dominance",
                               {"ld_radius":_ld_min.get(),"ld_max":_ld_max.get()}))
            if v_cv.get():
                tasks.append(("Surface Curvature", {}))
            if not tasks:
                messagebox.showinfo("Terrain Analysis","Tick at least one analysis."); return

            # Gather global settings
            global_cfg = {
                "ve":        float(_ve_var.get()),
                "depth_src": _depth_src_var.get(),
                "save":      _save_var.get(),
                "fmt_tif":   _fmt_tif.get(),
                "fmt_jpg":   _fmt_jpg.get(),
            }
            out_dir = None
            if global_cfg["save"] and (global_cfg["fmt_tif"] or global_cfg["fmt_jpg"]):
                out_dir = filedialog.askdirectory(title="Save terrain outputs to folder")
                if not out_dir: return
            win.destroy()
            self._run_rvt_analysis_batch(tasks, out_dir, global_cfg)

        ctk.CTkButton(_bot, text="⛰  Compute Selected Analyses",
                      fg_color="#1a4a2a", font=("Arial",12,"bold"), height=34,
                      command=_compute).pack(side="right", padx=4)

    def _run_rvt_analysis_batch(self, tasks, out_dir=None, cfg=None):
        """RVT terrain analyses at FULL RESOLUTION from the selected depth source.

        Key design decisions:
        - Uses full-resolution depth map (not the 1200px proxy) for proper GeoTIFF output
        - Depth source is read from the dropdown, NOT always depth_vis_p
        - High-freq / Ultra-HF filtering is applied BEFORE VE so VE scales the right signal
        - Results displayed as pure greyscale (no false colour) — same as RVT outputs
        - GeoTIFFs are float32 at native capture resolution (typically 50-200 MB each)
        """
        import threading, PIL.Image as _PIL
        from scipy.ndimage import uniform_filter
        if cfg is None:
            cfg = {"ve":5.0,"depth_src":"Standard (depth_vis_p)","fmt_tif":True,"fmt_jpg":False}

        prog = ctk.CTkToplevel(self); prog.title("Terrain Analysis")
        prog.geometry("480x110"); prog.attributes("-topmost", True)
        _lbl = ctk.CTkLabel(prog, text="Preparing…", font=("Arial",11)); _lbl.pack(pady=(14,4))
        _bar = ctk.CTkProgressBar(prog, width=440); _bar.pack(padx=20); _bar.set(0); prog.update()

        def _work():
          try:
            ve      = float(cfg.get("ve", 5.0))
            src_key = cfg.get("depth_src", "Standard (depth_vis_p)")

            # ── Select FULL RESOLUTION depth map from the chosen source ───────
            # IMPORTANT: use full-res arrays, not the proxy.
            # The proxy is 2500px max; the capture is 8682×11574 → 100MP GeoTIFFs.
            if "Frankot" in src_key:
                raw_full = getattr(self, "depth_vis_fc", None) or self.depth_vis_p
            else:
                raw_full = self.depth_vis_p

            raw_full = raw_full.astype(np.float32)
            H, W = raw_full.shape

            # Apply frequency filtering at full resolution before VE
            if "Ultra-High-Freq" in src_key:
                _sig = max(W, H) * 0.005
                raw_full = raw_full - cv2.GaussianBlur(raw_full, (0, 0), _sig)
            elif "High-Freq" in src_key:
                _sig = max(W, H) * 0.05
                raw_full = raw_full - cv2.GaussianBlur(raw_full, (0, 0), _sig)

            # Normalise to [0, ve] — VE determines apparent pixel-height range
            r_min, r_max = float(raw_full.min()), float(raw_full.max())
            if r_max - r_min > 1e-9:
                dem_full = ((raw_full - r_min) / (r_max - r_min) * ve).astype(np.float32)
            else:
                dem_full = raw_full.astype(np.float32)

            # For display we use a 1200px version (fast); for GeoTIFF we save full-res
            cap = min(1200, max(H, W))
            sc  = cap / max(H, W)
            dh, dw = max(1, int(H*sc)), max(1, int(W*sc))
            dem = cv2.resize(dem_full, (dw, dh), cv2.INTER_AREA)

            # PS normals at display resolution for fast hillshade preview
            nrm_full = getattr(self, "normals_full", None)
            nrm_d = (cv2.resize(nrm_full.astype(np.float32), (dw, dh), cv2.INTER_AREA)
                     if nrm_full is not None else None)

            def _to_grey_pil(arr):
                """Convert float32 array to 8-bit greyscale PIL Image for display.
                Applies 1–99 percentile stretch so features are visible.
                NO false colour — terrain outputs are always greyscale."""
                a = arr.astype(np.float32)
                p1, p99 = float(np.percentile(a, 1)), float(np.percentile(a, 99))
                a = np.clip((a - p1) / max(p99 - p1, 1e-9), 0, 1)
                u8 = (a * 255).astype(np.uint8)
                return _PIL.fromarray(u8, mode="L")

            def _show_grey(arr, name):
                img = _to_grey_pil(arr)
                self.after(0, lambda im=img, n=name:
                    self._show_terrain_result(im, f"⛰ {n}  (VE={ve:.1f})"))

            def _save_outputs(arr_full, name):
                """Save full-res float32 GeoTIFF and optional JPEG preview."""
                if not out_dir: return
                safe = name.replace(" ", "_").replace("/", "-")
                if cfg.get("fmt_tif", True):
                    path = os.path.join(out_dir, f"terrain_{safe}_f32.tif")
                    cv2.imwrite(path, arr_full.astype(np.float32),
                                [cv2.IMWRITE_TIFF_COMPRESSION, 1])
                if cfg.get("fmt_jpg", False):
                    p1, p99 = float(np.percentile(arr_full, 1)), float(np.percentile(arr_full, 99))
                    u8 = np.clip((arr_full - p1) / max(p99-p1, 1e-9) * 255, 0, 255).astype(np.uint8)
                    cv2.imwrite(os.path.join(out_dir, f"terrain_{safe}_preview.jpg"), u8,
                                [cv2.IMWRITE_JPEG_QUALITY, 95])

            # ── Shared gradient (display res) — computed once ─────────────────
            gy, gx = np.gradient(dem)
            gx = gx.astype(np.float32); gy = gy.astype(np.float32)
            slope_d  = np.arctan(np.sqrt(gx**2 + gy**2)).astype(np.float32)
            aspect_d = (np.arctan2(-gy, gx) % (2*np.pi)).astype(np.float32)

            def _hs_arr(az_deg, alt_deg, dem_in=None, gx_in=None, gy_in=None):
                """Hillshade using PS normals when available, else Sobel gradient."""
                d  = dem_in if dem_in is not None else dem
                gx_ = gx_in if gx_in is not None else gx
                gy_ = gy_in if gy_in is not None else gy
                az, al = np.radians(az_deg), np.radians(alt_deg)
                if nrm_d is not None and dem_in is None:
                    # PS normals: most accurate for manuscript surfaces
                    N = nrm_d.astype(np.float32)
                    if N.max() > 1.5: N = N / 127.5 - 1.0
                    N = N.reshape(-1, 3)
                    N /= np.maximum(np.linalg.norm(N, axis=1, keepdims=True), 1e-8)
                    L = np.array([np.sin(az)*np.cos(al), -np.cos(az)*np.cos(al),
                                  np.sin(al)], np.float32)
                    return np.clip(np.maximum(0, (N @ L).reshape(dh, dw)), 0, 1)
                # Slope/aspect from gradient
                sl = np.arctan(np.sqrt(gx_**2 + gy_**2)).astype(np.float32)
                asp = (np.arctan2(-gy_, gx_) % (2*np.pi)).astype(np.float32)
                return np.clip(
                    np.cos(np.pi/2-al)*np.cos(sl) + np.sin(np.pi/2-al)*np.sin(sl)*np.cos(az-asp),
                    0, 1).astype(np.float32)

            def _svf_scan(dem_in, r_px, n_dir, positive_opns=False, positive=True):
                """Yokoyama horizon scanning on VE-scaled DEM."""
                _h, _w = dem_in.shape
                yg = np.arange(_h, dtype=np.float32)[:,None].repeat(_w, axis=1)
                xg = np.arange(_w, dtype=np.float32)[None,:].repeat(_h, axis=0)
                acc = np.zeros((_h, _w), np.float32)
                for di in range(n_dir):
                    az = 2.0 * np.pi * di / n_dir
                    sdx = float(np.sin(az)); sdy = -float(np.cos(az))
                    best = np.full((_h, _w), -9999.0, np.float32)
                    for r in range(1, r_px + 1):
                        tx = np.clip(xg + r*sdx, 0, _w-1).astype(np.float32)
                        ty = np.clip(yg + r*sdy, 0, _h-1).astype(np.float32)
                        tz = cv2.remap(dem_in, tx, ty, cv2.INTER_LINEAR,
                                       borderMode=cv2.BORDER_REPLICATE)
                        tan_e = (tz - dem_in) / float(r)
                        best = np.maximum(best, tan_e)
                    horizon = np.arctan(best).astype(np.float32)
                    if positive_opns:
                        acc += (np.pi/2 - horizon) if positive else -(np.pi/2 - horizon)
                    else:
                        acc += np.cos(horizon) ** 2
                return acc / n_dir

            n_tasks = len(tasks)
            for ti, (name, params) in enumerate(tasks):
                self.after(0, lambda n=name, i=ti: (
                    _lbl.configure(text=f"{i+1}/{n_tasks}: {n}  (VE={ve:.1f}, {src_key[:18]})"),
                    _bar.set((i+1)/n_tasks)))
                try:
                    result_d   = None   # display-res float32
                    result_full = None  # full-res float32 for GeoTIFF

                    if name == "Hillshade":
                        az, al = params["hs_azi"], params["hs_alt"]
                        result_d = _hs_arr(az, al)
                        if out_dir:
                            # Full-res hillshade from depth gradient
                            gy_f, gx_f = np.gradient(dem_full)
                            result_full = _hs_arr(az, al, dem_full, gx_f.astype(np.float32), gy_f.astype(np.float32))
                        if params.get("shadow"):
                            shad = (np.cos(aspect_d - np.radians(params["hs_azi"])) < -0.15)
                            result_d = result_d * np.where(shad, 0.1, 1.0).astype(np.float32)

                    elif name == "Multi-Dir Hillshade":
                        nd, al = int(params["n_dirs"]), float(params["hs_alt"])
                        acc = np.zeros((dh, dw), np.float32)
                        for di in range(nd):
                            acc += _hs_arr(360*di/nd, al)
                        result_d = acc / nd

                    elif name == "Slope Gradient":
                        u = params.get("unit", "degree")
                        result_d = (np.degrees(slope_d) if u == "degree" else
                                    np.tan(slope_d) * 100 if u == "percent" else slope_d)

                    elif name == "SLRM":
                        r = int(params["radius"])
                        if HAS_RVT:
                            try: result_d = rvt.vis.slrm(dem, radius_cell=r)
                            except Exception: pass
                        if result_d is None:
                            result_d = dem - uniform_filter(dem, r*2+1)

                    elif name == "MSRM":
                        rmin, rmax = float(params["msrm_min"]), float(params["msrm_max"])
                        if HAS_RVT:
                            try: result_d = rvt.vis.msrm(dem, 1.0, rmin, rmax)
                            except Exception: pass
                        if result_d is None:
                            scales = np.linspace(max(0.5, rmin), rmax, 5)
                            acc2 = np.zeros_like(dem)
                            for s in scales:
                                acc2 += dem - cv2.GaussianBlur(dem, (0, 0), float(s))
                            result_d = acc2 / len(scales)

                    elif name == "SVF":
                        r, nd = int(params["svf_radius"]), int(params["svf_dirs"])
                        if HAS_RVT:
                            try:
                                result_d = np.clip(rvt.vis.sky_view_factor(
                                    dem, 1.0, compute_svf=True,
                                    svf_n_dir=nd, svf_r_max=r)["svf"], 0, 1)
                            except Exception: pass
                        if result_d is None:
                            result_d = _svf_scan(dem, r, nd)

                    elif name == "Anisotropic SVF":
                        r, nd = int(params["svf_radius"]), int(params["svf_dirs"])
                        az_sv = float(params.get("hs_azi", 315))
                        if HAS_RVT:
                            try:
                                aniso = 2 if params.get("aniso") == "high" else 1
                                result_d = np.clip(rvt.vis.sky_view_factor(
                                    dem, 1.0, compute_svf=False, compute_asvf=True,
                                    svf_n_dir=nd, svf_r_max=r,
                                    asvf_dir=az_sv, asvf_level=aniso)["asvf"], 0, 1)
                            except Exception: pass
                        if result_d is None:
                            svf = _svf_scan(dem, r, nd)
                            w_dir = np.clip(np.cos(aspect_d - np.radians(az_sv))*0.5+0.5, 0, 1)
                            result_d = np.clip(svf*(0.5+w_dir*0.5), 0, 1)

                    elif name == "Positive Openness":
                        r, nd = int(params["op_radius"]), int(params["svf_dirs"])
                        if HAS_RVT:
                            try:
                                result_d = cv2.normalize(rvt.vis.sky_view_factor(
                                    dem, 1.0, compute_svf=False, compute_opns=True,
                                    svf_n_dir=nd, svf_r_max=r)["opns"],
                                    None, 0, 1, cv2.NORM_MINMAX).astype(np.float32)
                            except Exception: pass
                        if result_d is None:
                            result_d = _svf_scan(dem, r, nd, positive_opns=True, positive=True)
                            result_d = cv2.normalize(result_d, None, 0, 1, cv2.NORM_MINMAX)

                    elif name == "Negative Openness":
                        r, nd = int(params["op_radius"]), int(params["svf_dirs"])
                        if HAS_RVT:
                            try:
                                result_d = cv2.normalize(rvt.vis.sky_view_factor(
                                    -dem, 1.0, compute_svf=False, compute_opns=True,
                                    svf_n_dir=nd, svf_r_max=r)["opns"],
                                    None, 0, 1, cv2.NORM_MINMAX).astype(np.float32)
                            except Exception: pass
                        if result_d is None:
                            result_d = _svf_scan(dem, r, nd, positive_opns=True, positive=False)
                            result_d = cv2.normalize(result_d, None, 0, 1, cv2.NORM_MINMAX)

                    elif name == "Local Dominance":
                        rmin, rmax = int(params["ld_radius"]), int(params["ld_max"])
                        if HAS_RVT:
                            try:
                                result_d = rvt.vis.local_dominance(dem, min_rad=rmin, max_rad=rmax)
                            except Exception: pass
                        if result_d is None:
                            lo = uniform_filter(dem, rmin*2+1)
                            hi = uniform_filter(dem, rmax*2+1)
                            diff = dem - (lo+hi)*0.5
                            p98 = float(np.percentile(np.abs(diff), 98)) + 1e-9
                            result_d = np.clip(0.5+diff/p98*0.5, 0, 1)

                    elif name == "Surface Curvature":
                        dx2 = cv2.Sobel(cv2.Sobel(dem, cv2.CV_32F, 1, 0), cv2.CV_32F, 1, 0)
                        dy2 = cv2.Sobel(cv2.Sobel(dem, cv2.CV_32F, 0, 1), cv2.CV_32F, 0, 1)
                        curv = (dx2 + dy2).astype(np.float32)
                        p2 = float(np.percentile(curv, 2)); p98 = float(np.percentile(curv, 98))
                        result_d = np.clip((curv-p2)/max(p98-p2, 1e-9), 0, 1)

                    if result_d is not None:
                        r_f32 = result_d.astype(np.float32)
                        _show_grey(r_f32, name)
                        # Full-res output: scale display result back to capture resolution
                        if out_dir:
                            if result_full is None:
                                # Bilinear upsample display result to full res for GeoTIFF
                                result_full = cv2.resize(r_f32, (W, H), cv2.INTER_LINEAR)
                            _save_outputs(result_full, name)

                except Exception as te:
                    print(f"[RVT] {name}: {te}")
                    import traceback; traceback.print_exc()

            self.after(0, lambda: prog.destroy())
          except Exception as e:
            import traceback; traceback.print_exc()
            self.after(0, lambda err=str(e): (prog.destroy(),
                messagebox.showerror("Terrain Analysis", err)))

        threading.Thread(target=_work, daemon=True).start()

    def _show_terrain_result(self, pil_img, title):
        """Show terrain analysis result — greyscale, no forensic adjustments."""
        win = ctk.CTkToplevel(self); win.title(title)
        win.geometry("1600x1000"); win.attributes("-topmost", True)
        win.after(300, lambda: win.attributes("-topmost", False))
        max_w, max_h = 1540, 900
        w, h = pil_img.size
        scale = min(max_w/w, max_h/h, 4.0)
        try:
            _rs = __import__("PIL").Image.Resampling.LANCZOS
        except AttributeError:
            _rs = __import__("PIL").Image.LANCZOS
        if abs(scale - 1.0) > 0.01:
            pil_img = pil_img.resize((int(w*scale), int(h*scale)), _rs)
        import PIL.ImageTk as _PILtk
        tk_img = _PILtk.PhotoImage(pil_img)
        lbl = tk.Label(win, image=tk_img, bg="#080808")
        lbl.image = tk_img; lbl.pack(expand=True, fill="both", padx=4, pady=4)
        ctk.CTkLabel(win, text=title, font=("Arial", 11, "bold"),
                     text_color="#4ade80").pack(pady=(0, 4))
        _btn = ctk.CTkFrame(win, fg_color="transparent"); _btn.pack(pady=(0,8))
        def _save():
            p = filedialog.asksaveasfilename(defaultextension=".tif",
                initialfile=f"{title.replace(' ','_').replace('⛰','')}.tif",
                filetypes=[("TIFF","*.tif"),("PNG","*.png")])
            if p: pil_img.save(p)
        ctk.CTkButton(_btn, text="Save Image", width=100, fg_color="#1a3a2a",
                      command=_save).pack(side="left", padx=4)
        ctk.CTkButton(_btn, text="Close", width=80, fg_color="#3a3a4a",
                      command=win.destroy).pack(side="left", padx=4)

    def export_gis_analysis_maps(self):
        """Export georeferenced 32-bit float GeoTIFFs for GIS terrain analysis."""
        if getattr(self, 'normals_full', None) is None:
            messagebox.showwarning("No Data", "Process scans first."); return
        f = self._export_dir("Select parent folder for GIS Analysis Maps", suffix="GIS_Analysis")
        if not f: return
        try:
            # Use the terrain caches computed during run_processing at working resolution.
            # These are the same maps used for display — so export is guaranteed to look
            # identical to the on-screen render, just saved as georeferenced 32-bit float.
            # Upsampled to full resolution with LANCZOS for archival quality.
            def _upsample(arr):
                if arr.shape != (self.h, self.w):
                    return cv2.resize(arr, (self.w, self.h), interpolation=cv2.INTER_LANCZOS4)
                return arr

            pos_opn = _upsample(getattr(self, '_pos_opn_full', self._svf_full)).astype(np.float32)
            neg_opn = _upsample(getattr(self, '_neg_opn_full', 1.0 - self._svf_full)).astype(np.float32)
            msrm    = _upsample(getattr(self, '_msrm_full',    np.zeros((self.h, self.w), np.float32))).astype(np.float32)
            curv    = _upsample(getattr(self, '_curv_full',    np.zeros((self.h, self.w), np.float32))).astype(np.float32)
            slope   = _upsample(getattr(self, '_slope_full',   np.zeros((self.h, self.w), np.float32))).astype(np.float32)
            loc_dom = _upsample(getattr(self, '_loc_dom_full', self._svf_full)).astype(np.float32)
            svf     = _upsample(self._svf_full).astype(np.float32)

            maps_to_save = {
                "1_positive_openness_32f.tif":     pos_opn,
                "2_negative_openness_32f.tif":     neg_opn,
                "3_multi_scale_relief_msrm_32f.tif": msrm,
                "4_surface_curvature_32f.tif":     curv,
                "5_slope_gradient_32f.tif":        slope,
                "6_local_dominance_32f.tif":       loc_dom,
                "7_sky_view_factor_32f.tif":       svf,
            }

            if HAS_RASTERIO:
                res_mm = 1.0
                try:
                    if float(self.scale_mm.get()) > 0 and getattr(self, 'drawn_scale_px', None):
                        res_mm = float(self.scale_mm.get()) / self.drawn_scale_px
                except Exception: pass
                _res_m = res_mm / 1000.0   # kept for metadata only
                # Pixel size = 1.0 so QGIS RVT search radii work as cell counts,
                # not as enormous sub-mm fractions.
                transform = from_origin(0, float(self.h), 1.0, 1.0)
                for name, data in maps_to_save.items():
                    with rasterio.open(
                        os.path.join(f, name), 'w', driver='GTiff',
                        height=self.h, width=self.w, count=1, dtype='float32',
                        crs='EPSG:32630', transform=transform
                    ) as dst:
                        dst.write(data, 1)
            else:
                for name, data in maps_to_save.items():
                    cv2.imwrite(os.path.join(f, name), data, [cv2.IMWRITE_TIFF_COMPRESSION, 1])

            rvt_note = "RVT installed — full quality Positive/Negative Openness and Local Dominance." \
                       if HAS_RVT else \
                       "RVT not installed — fallback algorithms used for Openness and Local Dominance.\n" \
                       "Install with: pip install rvt-py  for full precision."
            georef_note = "Georeferenced (rasterio, EPSG:32630)." if HAS_RASTERIO else \
                          "Not georeferenced (rasterio not installed). Plain 32-bit float TIFFs."

            messagebox.showinfo("GIS Analysis Maps Saved",
                f"7 maps saved to:\n{f}\n\n"
                f"  1. positive_openness — reveals convex ridges and edges\n"
                f"  2. negative_openness — reveals concave grooves and pits\n"
                f"  3. msrm              — multi-scale relief (scratches → form)\n"
                f"  4. surface_curvature — Laplacian scratch/ridge detector\n"
                f"  5. slope_gradient    — slope magnitude map\n"
                f"  6. local_dominance   — local high-point visibility\n"
                f"  7. sky_view_factor   — open-sky proportion per pixel\n\n"
                f"{rvt_note}\n{georef_note}")
        except Exception as e:
            messagebox.showerror("GIS Analysis Maps Error", str(e))

    def _show_layer_selector(self, panel_titles):
        """Modal dialog for choosing which layers to include in the publication sheet."""
        # ── Preset definitions ─────────────────────────────────────────────────
        _PRESETS = {
            "Minimum": {
                "1. Light Dome", "2. Light Vec. Dist.", "3. Pure Colour",
                "4. Normals", "5. Depth", "10. Heatmap", "11. Standard PBR",
                "13. Primary Hillshade",
            },
            "Standard": {
                "1. Light Dome", "2. Light Vec. Dist.", "3. Pure Colour",
                "4. Normals", "5. Depth", "6. Roughness", "8. AO Edge",
                "9. PCA", "10. Heatmap", "11. Standard PBR", "12. Robust PBR",
                "13. Primary Hillshade", "14. Multi-Dir Hillshade", "15. SVF",
                "21. Curvature", "22. MSRM", "24. SLRM",
                "T7. Hillshade (raking)",
            },
            "Inscription": {
                # Optimised for ink on parchment / incised text
                "3. Pure Colour", "4. Normals", "5. Depth",
                "8. AO Edge", "10. Heatmap", "11. Standard PBR",
                "13. Primary Hillshade", "14. Multi-Dir Hillshade",
                "21. Curvature", "24. SLRM",
                "T7. Hillshade (raking)",
            },
            "Coin / Seal": {
                # High-relief objects — specular + hillshade emphasis
                "3. Pure Colour", "4. Normals", "5. Depth",
                "6. Roughness", "8. AO Edge", "10. Heatmap",
                "11. Standard PBR", "12. Robust PBR",
                "13. Primary Hillshade", "14. Multi-Dir Hillshade",
                "15. SVF", "21. Curvature",
            },
            "Manuscript Full": {
                # Full scholarly analysis of a manuscript page
                "1. Light Dome", "2. Light Vec. Dist.", "3. Pure Colour",
                "4. Normals", "5. Depth", "6. Roughness",
                "7. Specular Variance", "8. AO Edge", "9. PCA",
                "10. Heatmap", "11. Standard PBR", "12. Robust PBR",
                "13. Primary Hillshade", "14. Multi-Dir Hillshade",
                "15. SVF", "21. Curvature", "22. MSRM", "24. SLRM",
                "T7. Hillshade (raking)",
            },
            "RTI Heritage": {
                # CHI/Factum-style heritage RTI documentation set
                "3. Pure Colour", "4. Normals", "10. Heatmap",
                "11. Standard PBR", "13. Primary Hillshade",
                "14. Multi-Dir Hillshade", "15. SVF", "21. Curvature",
            },
            "All": set(panel_titles),
        }

        result = [None]
        win = ctk.CTkToplevel(self)
        win.title("Publication Sheet — Select Panels")
        win.geometry("460x600"); win.grab_set()
        win.after(100, win.lift)

        # Header
        ctk.CTkLabel(win, text="Select Panels to Include",
                     font=("Arial", 14, "bold")).pack(pady=(14, 2))
        ctk.CTkLabel(win, text="Only ticked panels are rendered — unticked panels are skipped entirely.",
                     wraplength=420, font=("Arial", 10),
                     text_color="#888").pack(pady=(0, 6), padx=20)

        # Preset + select-all row
        prow = ctk.CTkFrame(win, fg_color="transparent")
        prow.pack(fill="x", padx=16, pady=(0, 4))
        ctk.CTkLabel(prow, text="Preset:", font=("Arial", 11)).pack(side="left")
        vars_ = []  # populated below

        def apply_preset(name):
            chosen = _PRESETS.get(name, set())
            for v, t in zip(vars_, panel_titles):
                v.set(t in chosen)

        for pname, clr in [("Minimum","#1a6b3a"),("Standard","#1a4a7a"),
                            ("Inscription","#4a3a1a"),("Coin / Seal","#3a1a4a"),
                            ("Manuscript Full","#1a4a4a"),("RTI Heritage","#3a3a1a"),
                            ("All","#6a2a8a")]:
            ctk.CTkButton(prow, text=pname, width=72, height=26,
                          fg_color=clr,
                          command=lambda n=pname: apply_preset(n)).pack(side="left", padx=(6,0))

        # Select all / Deselect all
        sarow = ctk.CTkFrame(win, fg_color="transparent")
        sarow.pack(fill="x", padx=16, pady=(0, 6))
        def sel_all():
            for v in vars_: v.set(True)
        def desel_all():
            for v in vars_: v.set(False)
        ctk.CTkButton(sarow, text="✔ Select All",   width=110, height=24,
                      fg_color="#2c3e50", command=sel_all).pack(side="left")
        ctk.CTkButton(sarow, text="✗ Deselect All", width=110, height=24,
                      fg_color="#4a1a1a", command=desel_all).pack(side="left", padx=(8,0))

        # Scrollable checkbox list
        scroll = ctk.CTkScrollableFrame(win)
        scroll.pack(fill="both", expand=True, padx=15, pady=4)
        _last_prefix = None
        _section_labels = {
            "1": "— Core Outputs —",
            "T": "— Topographic —",
            "F": "— Forensic / Spectral —",
        }
        for title in panel_titles:
            prefix = title[0]
            if prefix != _last_prefix and prefix in _section_labels:
                ctk.CTkLabel(scroll, text=_section_labels[prefix],
                             font=("Arial", 9, "bold"), text_color="#5a8aaa").pack(
                             anchor="w", padx=10, pady=(6, 0))
                _last_prefix = prefix
            v = tk.BooleanVar(value=True)
            colour = "#7dd4f8" if prefix == "F" else None
            _ckw = {"text_color": colour} if colour else {}
            ctk.CTkCheckBox(scroll, text=title, variable=v, **_ckw).pack(
                anchor="w", pady=2, padx=10)
            vars_.append(v)

        # Crop option — shown only if crop is active
        _crop_var = tk.BooleanVar(value=bool(getattr(self, 'crop_box', None)))
        if getattr(self, 'crop_box', None):
            _crop_row = ctk.CTkFrame(win, fg_color="#0a2a1a", corner_radius=4)
            _crop_row.pack(fill="x", padx=16, pady=(0, 4))
            ctk.CTkCheckBox(_crop_row,
                text="✂ Respect active crop region",
                variable=_crop_var, font=("Arial", 11), text_color="#4ade80").pack(
                side="left", padx=12, pady=6)
            x1c,y1c,x2c,y2c = self.crop_box
            ctk.CTkLabel(_crop_row,
                text=f"{x2c-x1c}×{y2c-y1c}px",
                font=("Arial", 10), text_color="#64748b").pack(side="right", padx=12)

        # Generate / Cancel buttons
        btn_row = ctk.CTkFrame(win, fg_color="transparent")
        btn_row.pack(pady=10, fill="x", padx=20)
        def on_ok():
            result[0] = ([v.get() for v in vars_], _crop_var.get())
            win.grab_release(); win.destroy()
        def on_cancel():
            win.grab_release(); win.destroy()
        ctk.CTkButton(btn_row, text="Generate Sheet", fg_color="#2980b9",
                      command=on_ok).pack(side="left", expand=True, fill="x", padx=(0, 5))
        ctk.CTkButton(btn_row, text="Cancel", fg_color="#7f8c8d",
                      command=on_cancel).pack(side="right", expand=True, fill="x", padx=(5, 0))
        win.wait_window()
        return result[0]

