    def export_poi_positions(self):
        """Export the active PoI / light position data as a CSV for metrological traceability."""
        poi = getattr(self, 'poi_coords', None)
        if not poi:
            messagebox.showinfo("Export PoI", "No PoI data loaded. Select a stand profile or import a CSV first."); return
        p = filedialog.asksaveasfilename(
            defaultextension=".csv",
            filetypes=[("CSV","*.csv")],
            initialfile=f"{self.object_id_var.get() or 'helio'}_poi_positions.csv")
        if not p: return
        try:
            with open(p, 'w', newline='') as f:
                w = csv.writer(f)
                w.writerow(["name", "X_mm", "Y_mm", "Z_mm", "notes"])
                profile = self.stand_profile_var.get()
                for name, (x, y, z) in poi.items():
                    note = "acquisition plane origin" if name == "Origin" else \
                           "camera position" if name == "Camera" else \
                           f"light source — {profile}"
                    w.writerow([name, f"{x:.4f}", f"{y:.4f}", f"{z:.4f}", note])
            messagebox.showinfo("PoI Exported",
                f"3D light positions saved to:\n{p}\n\n"
                f"Profile: {profile}\n"
                f"Points: {len(poi)}\n\n"
                "Include this file with your dataset deposit for metrological traceability.")
        except Exception as e:
            messagebox.showerror("PoI Export Error", str(e))

    def run_normal_qc_report(self):
        """
        Compute a quantitative QC report on the current PS normal map quality.

        If a flat reference is loaded:
          • Compares object normals against the ideal [0,0,1] corrected for the
            flat field, producing per-pixel angular error (degrees).

        Always reports:
          • Mean, median, std angular deviation from the hemisphere mean
          • 90th / 95th / 99th percentile values
          • Spatial heatmap of angular deviation
          • Frequency-split (LP / HP) normal statistics

        Target thresholds (Gaiani et al. 2025):
          Overall MAE < 2°, LP component MAE < 0.5°, HP MAE < 3°
        """
        if getattr(self, 'normals_full', None) is None:
            messagebox.showinfo("Normal QC", "Process scans first."); return
        try:
            n  = self.normals_full.astype(np.float32)
            h, w = n.shape[:2]

            # Angular deviation from mean viewing direction (approx [0,0,1] for well-focused PS)
            mean_n = np.mean(n.reshape(-1, 3), axis=0)
            mean_n /= (np.linalg.norm(mean_n) + 1e-9)
            dot = np.clip(np.einsum('hwc,c->hw', n, mean_n), -1.0, 1.0)
            ang_deg = np.degrees(np.arccos(dot))

            # If flat reference available, compute deviation from corrected ideal
            if self.flat_ref_normals is not None and self.flat_correction_var.get():
                flat = cv2.resize(self.flat_ref_normals, (w, h))
                flat_ideal = np.array([0.0, 0.0, 1.0], dtype=np.float32)
                flat_dot = np.clip(np.einsum('hwc,c->hw', flat, flat_ideal), -1.0, 1.0)
                flat_ang = np.degrees(np.arccos(flat_dot))
                residual_ang = np.abs(ang_deg - flat_ang)
            else:
                residual_ang = ang_deg

            # LP / HP split using Gaussian (σ = qc_lp_sigma_var)
            sigma = float(self.qc_lp_sigma_var.get())
            lp_ang = cv2.GaussianBlur(residual_ang.astype(np.float32), (0, 0), sigmaX=sigma)
            hp_ang = np.abs(residual_ang - lp_ang)

            stats = {
                "Mean angular deviation (°)":        float(np.mean(residual_ang)),
                "Median (°)":                         float(np.median(residual_ang)),
                "Std dev (°)":                        float(np.std(residual_ang)),
                "90th percentile (°)":                float(np.percentile(residual_ang, 90)),
                "95th percentile (°)":                float(np.percentile(residual_ang, 95)),
                "99th percentile (°)":                float(np.percentile(residual_ang, 99)),
                "LP component MAE (°)":               float(np.mean(lp_ang)),
                "HP component MAE (°)":               float(np.mean(hp_ang)),
                "Pixels > 1° (%)":                    float(np.mean(residual_ang > 1.0) * 100),
                "Pixels > 3° (%)":                    float(np.mean(residual_ang > 3.0) * 100),
                "LP σ used (px)":                     float(sigma),
            }
            # Quality rating
            mae = stats["Mean angular deviation (°)"]
            lp_mae = stats["LP component MAE (°)"]
            if mae < 1.0 and lp_mae < 0.5:
                rating = "🟢 Metrological Grade  (MAE < 1°, LP-MAE < 0.5°)"
            elif mae < 3.0 and lp_mae < 1.5:
                rating = "🟡 Research Grade  (MAE < 3°)"
            else:
                rating = "🔴 Exploratory  (MAE ≥ 3° — consider better calibration)"

            # Display heatmap + stats
            fig, axes = plt.subplots(1, 3, figsize=(16, 5), facecolor="#1a2030")
            for ax in axes:
                ax.set_facecolor("#0e1520")
                ax.tick_params(colors="#aabbcc")
                for spine in ax.spines.values(): spine.set_edgecolor("#444")

            im0 = axes[0].imshow(residual_ang, cmap="hot", vmin=0, vmax=5)
            axes[0].set_title("Angular Deviation (°)", color="white")
            plt.colorbar(im0, ax=axes[0]).ax.tick_params(colors="#aabbcc")

            im1 = axes[1].imshow(lp_ang, cmap="coolwarm", vmin=0, vmax=3)
            axes[1].set_title(f"Low-Freq Component (σ={sigma:.0f}px)", color="white")
            plt.colorbar(im1, ax=axes[1]).ax.tick_params(colors="#aabbcc")

            axes[2].hist(residual_ang.ravel(), bins=60, color="#5599cc", edgecolor="#2266aa",
                         range=(0, 10))
            axes[2].axvline(mae, color="#ff8844", lw=2, label=f"Mean={mae:.2f}°")
            axes[2].axvline(1.0, color="#44ff88", lw=1.5, ls="--", label="1° target")
            axes[2].set_xlabel("Angular Error (°)"); axes[2].set_ylabel("Pixel count")
            axes[2].set_title("Error Distribution", color="white")
            axes[2].tick_params(colors="#aabbcc")
            axes[2].xaxis.label.set_color("#aabbcc"); axes[2].yaxis.label.set_color("#aabbcc")
            leg = axes[2].legend(fontsize=8); [t.set_color("#dddddd") for t in leg.get_texts()]

            obj_id = self.object_id_var.get() or "—"
            fig.suptitle(
                f"Normal Map QC Report  |  {obj_id}  |  {time.strftime('%Y-%m-%d')}\n"
                f"Solver: {self.normal_engine.get()}  |  {rating}",
                color="white", fontsize=11)
            fig.tight_layout()

            # Print stats to console / popup
            stats_txt = "\n".join(f"  {k:<35} {v:.3f}" if isinstance(v,float) else f"  {k:<35} {v}"
                                   for k, v in stats.items())
            print(f"\n[HELIO QC Report — {obj_id}]\n{stats_txt}\nRating: {rating}\n")
            plt.show()
            messagebox.showinfo("Normal QC Report",
                f"Quality Rating: {rating}\n\n"
                f"Mean angular deviation : {mae:.3f}°\n"
                f"LP component MAE       : {lp_mae:.3f}°\n"
                f"HP component MAE       : {stats['HP component MAE (°)']:.3f}°\n\n"
                f"Target thresholds (Gaiani et al. 2025):\n"
                f"  Overall MAE  ≤ 2°\n  LP-MAE       ≤ 0.5°\n  HP-MAE       ≤ 3°")
        except Exception as e:
            messagebox.showerror("Normal QC Error", str(e))

