    def show_capture_metadata_panel(self):
        """Metadata panel: save/load JSON, HELIO Pro defaults."""
        win = tk.Toplevel(self); win.title("Capture Metadata Sheet")
        win.geometry("620x740"); win.configure(bg="#1a2030"); win.resizable(True, True)
        try: win.iconbitmap(self.iconbitmap())
        except Exception: pass

        _DEFAULTS = {
            "institution": "HELIO Pro",
            "collection":  "Cultural Heritage Imaging Lab",
            "operator":    "Scott Maloney",
            "camera":      "Phase One IQ4 100MP",
            "sensor":      "100MP CMOS (8682x11574)",
            "pixel_pitch": "3.76",
            "capture_date": time.strftime("%Y-%m-%d"),
            "img_count":   str(len(getattr(self,"plate_paths",[]) or [])),
        }
        if not hasattr(self,"_capture_meta") or not self._capture_meta:
            self._capture_meta = {}
        meta = dict(_DEFAULTS)
        meta.update(self._capture_meta)

        fields = [
            ("Institution",           "institution",  "e.g. HELIO Pro"),
            ("Department/Collection", "collection",   "e.g. Cultural Heritage Imaging Lab"),
            ("Operator Name",         "operator",     "Name of scanning technician"),
            ("Object Title",          "title",        "e.g. Intaglio seal, limestone"),
            ("Date of Capture",       "capture_date", time.strftime("%Y-%m-%d")),
            ("Camera Model",          "camera",       "e.g. Phase One IQ4 100MP"),
            ("Lens",                  "lens",         "e.g. Schneider 120mm Macro"),
            ("Sensor (MPx)",          "sensor",       "e.g. 100MP CMOS"),
            ("Pixel Pitch (um)",      "pixel_pitch",  "e.g. 3.76"),
            ("Lighting Type",         "lights",       "e.g. Relio2 LED x8, 4000K"),
            ("Stand / Rig",           "stand",        "e.g. Horizontal Stand"),
            ("Image Count (PS)",      "img_count",    ""),
            ("Working Distance (mm)", "working_dist", "e.g. 430"),
            ("Scale (mm/px)",         "scale_mmpx",   "e.g. 0.042"),
            ("Notes",                 "notes",        "Any deviations from standard protocol"),
            ("DOI / Reference",       "doi",          "e.g. 10.3390/heritage8040129"),
        ]

        entries = {}
        scr_c = tk.Canvas(win, bg="#1a2030", highlightthickness=0)
        scr_s = tk.Scrollbar(win, command=scr_c.yview)
        scr_c.configure(yscrollcommand=scr_s.set)
        scr_s.pack(side="right", fill="y"); scr_c.pack(fill="both", expand=True, padx=8, pady=4)
        inner = tk.Frame(scr_c, bg="#1a2030")
        cw = scr_c.create_window((0,0), window=inner, anchor="nw")
        inner.bind("<Configure>", lambda e: scr_c.configure(scrollregion=scr_c.bbox("all")))
        scr_c.bind("<Configure>", lambda e: scr_c.itemconfig(cw, width=e.width-4))

        tk.Label(inner, text="Capture Metadata Sheet", bg="#1a2030",
                 fg="#5dade2", font=("Arial", 13, "bold")).grid(row=0, column=0,
                 columnspan=2, pady=(8,2), sticky="w", padx=6)
        tk.Label(inner, text="Defaults: HELIO Pro  |  Scott Maloney  |  Phase One IQ4",
                 bg="#1a2030", fg="#3a5a7a", font=("Arial", 8)).grid(row=1, column=0,
                 columnspan=2, sticky="w", padx=6, pady=(0,8))

        for r, (label, key, hint) in enumerate(fields, start=2):
            tk.Label(inner, text=label+":", bg="#1a2030", fg="#aabbcc",
                     font=("Arial", 10), anchor="e", width=24
                     ).grid(row=r, column=0, sticky="e", padx=(6,4), pady=3)
            var = tk.StringVar(value=meta.get(key, hint))
            e = tk.Entry(inner, textvariable=var, bg="#2a3545", fg="white",
                         font=("Arial", 10), insertbackground="white", width=42, relief="flat")
            e.grid(row=r, column=1, sticky="ew", pady=3, padx=(0,6))
            entries[key] = var
        inner.columnconfigure(1, weight=1)

        def _collect():
            for k, v in entries.items():
                self._capture_meta[k] = v.get().strip()
            if not self._capture_meta.get("img_count") and hasattr(self, "plate_paths"):
                self._capture_meta["img_count"] = str(len(self.plate_paths or []))

        def _save():
            _collect()
            messagebox.showinfo("Saved", "Metadata saved and will be embedded in all exports.")
            win.destroy()

        def _save_json():
            _collect()
            obj = self.object_id_var.get() or "metadata"
            p = filedialog.asksaveasfilename(defaultextension=".json",
                filetypes=[("JSON","*.json")], initialfile=f"{obj}_metadata.json")
            if not p: return
            with open(p, "w") as f: json.dump(self._capture_meta, f, indent=2)
            messagebox.showinfo("Saved", f"JSON saved:\n{p}")

        def _load_json():
            p = filedialog.askopenfilename(filetypes=[("JSON","*.json"),("All","*.*")])
            if not p: return
            try:
                with open(p) as f: loaded = json.load(f)
                self._capture_meta.update(loaded)
                for k, v in entries.items():
                    if k in loaded: v.set(loaded[k])
                messagebox.showinfo("Loaded", f"Metadata loaded:\n{p}")
            except Exception as ex:
                messagebox.showerror("Load Error", str(ex))

        def _export_csv():
            _collect()
            p = filedialog.asksaveasfilename(defaultextension=".csv",
                filetypes=[("CSV","*.csv")],
                initialfile=f"{self.object_id_var.get() or 'helio'}_metadata.csv")
            if not p: return
            with open(p, "w", newline="") as f:
                cw2 = csv.writer(f)
                cw2.writerow(["Field","Value"])
                for k,v in self._capture_meta.items(): cw2.writerow([k,v])
            messagebox.showinfo("Saved", f"CSV saved:\n{p}")

        def _reset():
            for k, v in entries.items():
                v.set(_DEFAULTS.get(k, ""))

        btn = tk.Frame(inner, bg="#1a2030")
        btn.grid(row=len(fields)+3, column=0, columnspan=2, pady=12, sticky="ew")
        for txt, cmd, col in [
            ("Save",       _save,       "#2c6e49"),
            ("Save JSON",  _save_json,  "#1a4a6b"),
            ("Load JSON",  _load_json,  "#1a4a6b"),
            ("Export CSV", _export_csv, "#1a4a6b"),
            ("Defaults",   _reset,      "#4a2a0a"),
            ("Close",      win.destroy, "#3a3a3a"),
        ]:
            tk.Button(btn, text=txt, command=cmd, bg=col, fg="white",
                      font=("Arial", 10), padx=10, relief="flat").pack(side="left", padx=3)

